#!/usr/bin/env node

import { existsSync, mkdirSync, writeFileSync, readFileSync, readdirSync, copyFileSync, statSync } from "fs";
import { join, resolve, dirname } from "path";
import { fileURLToPath, pathToFileURL } from "url";
import { execSync, execFileSync } from "child_process";

const __dirname = dirname(fileURLToPath(import.meta.url));

const command = process.argv[2];

if (!command || command === "help" || command === "--help") {
  console.log(`
team11-memory -- Persistent memory for Team11 multi-agent orchestration

Commands:
  init          Set up Team11 Memory in the current project
  init --sync   Set up with Turso sync prompts
  seed          Import existing .team11/findings/*.md into the database
  stats         Show database statistics
  decay         Run confidence decay across all entries
  help          Show this help message

Usage:
  npx team11-memory init     # In your project root
  npx team11-memory seed     # After adding findings
  npx team11-memory stats    # Check what's in the DB
  npx team11-memory decay    # Run weekly decay
`);
  process.exit(0);
}

if (command === "init") {
  init();
} else if (command === "seed") {
  runSeed();
} else if (command === "stats") {
  runStats();
} else if (command === "decay") {
  runDecay();
} else {
  console.error(`Unknown command: ${command}. Run 'team11-memory help' for usage.`);
  process.exit(1);
}

function init() {
  const projectRoot = resolve(process.cwd());
  const team11Dir = join(projectRoot, ".team11");
  const mcpServerDir = join(team11Dir, "mcp-server");
  const projectName = projectRoot.split(/[/\\]/).pop() || "project";

  console.log(`\nInitializing Team11 Memory in: ${projectRoot}\n`);

  // Step 1: Create directories
  console.log("Creating .team11/ directory structure...");
  const dirs = [
    join(team11Dir, "findings"),
    join(team11Dir, "logs"),
    join(team11Dir, "checkpoints"),
    join(team11Dir, "stale"),
    join(team11Dir, "proposals"),
    join(team11Dir, "inboxes"),
    join(mcpServerDir, "src", "tools"),
    join(mcpServerDir, "src", "scripts"),
  ];
  for (const dir of dirs) {
    mkdirSync(dir, { recursive: true });
  }

  // Step 2: Copy the live MCP server source into the target project.
  // Previously this embedded a hand-maintained snapshot of every source file
  // (writeSourceFiles), which drifted out of sync with db.ts and shipped a
  // born-broken schema (missing contradictions/active_edits/operators/
  // file_summaries tables). Copying the live source tree guarantees the
  // canonical, current schema (D3 fix). The DB itself is created from the
  // canonical initDb in Step 9b below.
  console.log("Copying MCP server source files...");
  copyLiveSource(mcpServerDir);

  // Step 3: Write package.json
  writeFileSync(join(mcpServerDir, "package.json"), JSON.stringify({
    name: "team11-memory",
    version: "1.0.0",
    description: "Persistent memory MCP server for Team11 multi-agent orchestration",
    type: "module",
    main: "dist/index.js",
    bin: { "team11-memory": "dist/cli.js" },
    scripts: {
      build: "tsc",
      start: "node dist/index.js",
      seed: "node dist/scripts/seed.js"
    },
    dependencies: {
      "@modelcontextprotocol/sdk": "^1.0.0",
      "better-sqlite3": "^11.0.0",
      "zod": "^3.25.0",
      "sqlite-vec": "^0.1.9",
      "@huggingface/transformers": "^4.0.0",
      "@libsql/client": "^0.17.2"
    },
    devDependencies: {
      "@types/better-sqlite3": "^7.6.0",
      "@types/node": "^22.0.0",
      typescript: "^5.5.0"
    }
  }, null, 2) + "\n");

  // Step 4: Write tsconfig.json
  writeFileSync(join(mcpServerDir, "tsconfig.json"), JSON.stringify({
    compilerOptions: {
      target: "ES2022",
      module: "NodeNext",
      moduleResolution: "NodeNext",
      outDir: "dist",
      rootDir: "src",
      strict: true,
      esModuleInterop: true,
      declaration: true,
      skipLibCheck: true,
      resolveJsonModule: true,
      forceConsistentCasingInFileNames: true
    },
    include: ["src/**/*"]
  }, null, 2) + "\n");

  // Step 5: Install dependencies
  console.log("Installing dependencies (this may take a minute)...");
  try {
    execSync("npm install", { cwd: mcpServerDir, stdio: "inherit" });
  } catch (_err) {
    console.error("npm install failed. You may need to run it manually:");
    console.error(`  cd ${mcpServerDir} && npm install`);
  }

  // Step 6: Build TypeScript
  console.log("Building TypeScript...");
  try {
    execSync("npm run build", { cwd: mcpServerDir, stdio: "inherit" });
  } catch (_err) {
    console.error("Build failed. You may need to run it manually:");
    console.error(`  cd ${mcpServerDir} && npm run build`);
  }

  // Step 6b: Initialize the database from the CANONICAL schema (D3 fix).
  // Run the freshly-built dist/db.js::initDb in a separate node process so the
  // full, current schema (findings, pheromones, contradictions, active_edits,
  // operators, file_summaries, FTS5 + vec0) is created up front — not lazily
  // from a possibly-stale snapshot. execFileSync (no shell) keeps the
  // server-controlled paths from being shell-interpreted.
  console.log("Initializing database (canonical schema)...");
  try {
    const dbJsUrl = pathToFileURL(join(mcpServerDir, "dist", "db.js")).href;
    const dbPath = join(team11Dir, "memory.db").replace(/\\/g, "/");
    const initScript =
      `import(${JSON.stringify(dbJsUrl)}).then(m => { ` +
      `const db = m.initDb(${JSON.stringify(dbPath)}); ` +
      `const t = db.prepare("SELECT COUNT(*) as c FROM sqlite_master WHERE type='table'").get(); ` +
      `console.log('  Database ready (' + t.c + ' tables)'); db.close(); });`;
    execFileSync(process.execPath, ["--input-type=module", "-e", initScript], {
      cwd: mcpServerDir,
      stdio: "inherit",
    });
  } catch (_err) {
    console.error("Database init deferred — it will be created on first MCP server start.");
  }

  // Step 7: Create .mcp.json (merge if exists)
  console.log("Configuring MCP server discovery...");
  const mcpJsonPath = join(projectRoot, ".mcp.json");
  let mcpConfig: Record<string, unknown> = { mcpServers: {} };
  if (existsSync(mcpJsonPath)) {
    try {
      mcpConfig = JSON.parse(readFileSync(mcpJsonPath, "utf8"));
      if (!mcpConfig.mcpServers) mcpConfig.mcpServers = {};
    } catch { /* start fresh */ }
  }
  // Use forward slashes for Node.js compatibility
  const indexPath = join(mcpServerDir, "dist", "index.js").replace(/\\/g, "/");
  const dbPath = join(team11Dir, "memory.db").replace(/\\/g, "/");
  (mcpConfig.mcpServers as Record<string, unknown>)["team11-memory"] = {
    command: "node",
    args: [indexPath],
    env: { TEAM11_MEMORY_DB: dbPath }
  };
  writeFileSync(mcpJsonPath, JSON.stringify(mcpConfig, null, 2) + "\n");

  // Step 8: Create config.json
  console.log("Creating default config...");
  const configPath = join(team11Dir, "config.json");
  if (!existsSync(configPath)) {
    writeFileSync(configPath, JSON.stringify({
      mode: "solo",
      operator: null,
      repo: null,
      sync: {
        enabled: false,
        provider: "turso",
        url: "",
        token: "",
        syncInterval: 60
      }
    }, null, 2) + "\n");
  } else {
    console.log("  config.json already exists, skipping.");
  }

  // Step 9: Update .gitignore
  console.log("Updating .gitignore...");
  const gitignorePath = join(projectRoot, ".gitignore");
  let gitignore = "";
  if (existsSync(gitignorePath)) {
    gitignore = readFileSync(gitignorePath, "utf8");
  }
  if (!gitignore.includes(".team11/")) {
    const addition = "\n# Team11 (ephemeral agent state, secrets, database)\n.team11/\n";
    writeFileSync(gitignorePath, gitignore + addition);
  }

  // Step 10: Seed if findings exist
  const findingsDir = join(team11Dir, "findings");
  const findingFiles = existsSync(findingsDir)
    ? readdirSync(findingsDir).filter(f => f.endsWith(".md"))
    : [];
  if (findingFiles.length > 0) {
    console.log(`Found ${findingFiles.length} existing findings. Seeding database...`);
    try {
      execSync("npm run seed", { cwd: mcpServerDir, stdio: "inherit" });
    } catch (_err) {
      console.error("Seed failed. Run manually: cd .team11/mcp-server && npm run seed");
    }
  }

  // Done!
  console.log(`
Team11 Memory initialized!

  Database:    .team11/memory.db
  MCP Server:  .team11/mcp-server/
  Config:      .team11/config.json
  Tools:       16 MCP tools registered

  Restart Claude Code to activate the memory server.

  For team sync (optional):
    1. Create a Turso database: turso db create team11-memory-${projectName}
    2. Get URL: turso db show team11-memory-${projectName} --url
    3. Get token: turso db tokens create team11-memory-${projectName}
    4. Edit .team11/config.json -- set sync.enabled=true, paste URL+token
    5. Share URL+token with coworkers
`);
}

function runSeed() {
  const mcpServerDir = join(process.cwd(), ".team11", "mcp-server");
  if (!existsSync(mcpServerDir)) {
    console.error("No .team11/mcp-server/ found. Run 'team11-memory init' first.");
    process.exit(1);
  }
  execSync("npm run seed", { cwd: mcpServerDir, stdio: "inherit" });
}

function runStats() {
  const dbPath = join(process.cwd(), ".team11", "memory.db");
  if (!existsSync(dbPath)) {
    console.error("No .team11/memory.db found. Run 'team11-memory init' first.");
    process.exit(1);
  }
  import("better-sqlite3").then(({ default: Database }) => {
    const db = new Database(dbPath);
    const total = (db.prepare("SELECT COUNT(*) as c FROM findings").get() as Record<string, number>).c;
    const byType = db.prepare("SELECT type, COUNT(*) as c FROM findings GROUP BY type").all() as Array<{ type: string; c: number }>;
    const pheromones = (db.prepare("SELECT COUNT(*) as c FROM pheromones").get() as Record<string, number>).c;
    console.log(`\nTeam11 Memory Stats`);
    console.log(`  Total entries: ${total}`);
    for (const t of byType) {
      console.log(`    ${t.type}: ${t.c}`);
    }
    console.log(`  Pheromone trails: ${pheromones}`);
    console.log(`  Database: ${dbPath}\n`);
    db.close();
  });
}

function runDecay() {
  const dbPath = join(process.cwd(), ".team11", "memory.db");
  if (!existsSync(dbPath)) {
    console.error("No .team11/memory.db found. Run 'team11-memory init' first.");
    process.exit(1);
  }
  import("better-sqlite3").then(({ default: Database }) => {
    const db = new Database(dbPath);
    import("./decay.js").then(({ runDecay: decay }) => {
      const result = decay(db);
      console.log(`\nConfidence Decay Results:`);
      console.log(`  Updated: ${result.updated}`);
      console.log(`  Flagged (< 50%): ${result.flagged}`);
      console.log(`  Archived (< 25%): ${result.archived}`);
      if (result.flaggedEntries.length > 0) {
        console.log(`\n  Stale entries:`);
        for (const e of result.flaggedEntries) {
          console.log(`    [${Math.round(e.confidence * 100)}%] #${e.id}: ${e.title}`);
        }
      }
      if (result.archivedEntries.length > 0) {
        console.log(`\n  Archived entries:`);
        for (const e of result.archivedEntries) {
          console.log(`    [${Math.round(e.confidence * 100)}%] #${e.id}: ${e.title}`);
        }
      }
      db.close();
    });
  });
}

// -----------------------------------------------------------------------
// copyLiveSource -- copy the live MCP server source tree into a target
// project (replaces the old writeSourceFiles, which embedded a hand-
// maintained snapshot of every source file that drifted out of sync with
// db.ts and shipped a born-broken schema — D3 fix). The DB is created from
// the canonical initDb (see Step 9b in init()), so the schema is always
// current regardless of this copy.
// -----------------------------------------------------------------------

/** Walk up from this module to the MCP server package root (has package.json + src/). */
function findLiveSourceRoot(): string {
  let dir = __dirname;
  for (let i = 0; i < 6; i++) {
    if (existsSync(join(dir, "package.json")) && existsSync(join(dir, "src"))) return dir;
    dir = resolve(dir, "..");
  }
  throw new Error("Could not locate live MCP server source root (no package.json + src/ found)");
}

/** Recursively copy a directory, excluding build artifacts. Returns file count. */
function copyDirRecursive(src: string, dest: string, exclude: string[] = []): number {
  let count = 0;
  mkdirSync(dest, { recursive: true });
  for (const entry of readdirSync(src)) {
    if (exclude.includes(entry)) continue;
    const srcPath = join(src, entry);
    const destPath = join(dest, entry);
    if (statSync(srcPath).isDirectory()) {
      count += copyDirRecursive(srcPath, destPath, exclude);
    } else {
      copyFileSync(srcPath, destPath);
      count++;
    }
  }
  return count;
}

/**
 * Copy the live `src/` tree from this package into the target project's
 * mcp-server directory. No-op (with a notice) when init runs inside the same
 * package that hosts the source, to avoid copying a directory onto itself.
 */
function copyLiveSource(mcpServerDir: string): void {
  const liveRoot = findLiveSourceRoot();
  if (resolve(liveRoot) === resolve(mcpServerDir)) {
    console.log("  MCP server source already in place (same package) — skipping copy.");
    return;
  }
  const copied = copyDirRecursive(
    join(liveRoot, "src"),
    join(mcpServerDir, "src"),
    ["node_modules", "dist", ".git"],
  );
  console.log("  Copied " + copied + " source files");
}

// Retained for backward compatibility — delegates to the live-source copy.
// The stale embedded snapshot below is unreachable and kept only as a diff
// reference (regenerated from the CURRENT src/ tree by generate-cli.cjs); it
// is no longer used by init().
function writeSourceFiles(mcpServerDir: string) {
  copyLiveSource(mcpServerDir);
  return;

  // eslint-disable-next-line no-unreachable
  const files: Array<{ path: string; content: string }> = [];

  files.push({ path: "src/index.ts", content: "import { McpServer } from \"@modelcontextprotocol/sdk/server/mcp.js\";\nimport { StdioServerTransport } from \"@modelcontextprotocol/sdk/server/stdio.js\";\nimport { initDb } from \"./db.js\";\nimport { initEmbeddings } from \"./embeddings.js\";\nimport { registerTools } from \"./tools/index.js\";\nimport { loadSyncConfig, initSync, shutdownSync } from \"./sync.js\";\nimport { resolve, isAbsolute, dirname } from \"node:path\";\nimport { existsSync } from \"node:fs\";\nimport { fileURLToPath } from \"node:url\";\n\n/**\n * Find the project root by walking up from a starting directory\n * until we find a .team11/ directory.\n */\nfunction findProjectRoot(startDir: string): string | null {\n  let dir = startDir;\n  while (true) {\n    if (existsSync(resolve(dir, \".team11\"))) {\n      return dir;\n    }\n    const parent = dirname(dir);\n    if (parent === dir) break; // reached filesystem root\n    dir = parent;\n  }\n  return null;\n}\n\n/**\n * Resolve the database path. If it's relative, resolve it relative to:\n *   1. PROJECT_ROOT env var (if set)\n *   2. The project root (found by walking up from __dirname to find .team11/)\n *   3. Fall back to CWD (original behavior)\n */\nfunction resolveDbPath(raw: string): string {\n  if (isAbsolute(raw)) return raw;\n\n  // Try PROJECT_ROOT env var first\n  if (process.env.PROJECT_ROOT) {\n    return resolve(process.env.PROJECT_ROOT, raw);\n  }\n\n  // Walk up from script location to find project root\n  const __filename = fileURLToPath(import.meta.url);\n  const __dirname = dirname(__filename);\n  const projectRoot = findProjectRoot(__dirname);\n  if (projectRoot) {\n    return resolve(projectRoot, raw);\n  }\n\n  // Fallback: resolve relative to CWD\n  return resolve(raw);\n}\n\nconst server = new McpServer({\n  name: \"team11-memory\",\n  version: \"1.0.0\",\n  description: \"Persistent memory for Team11 multi-agent orchestration\",\n});\n\n// Initialize database — path configurable via env var\nconst rawDbPath = process.env.TEAM11_MEMORY_DB || \".team11/memory.db\";\nconst dbPath = resolveDbPath(rawDbPath);\nconst db = initDb(dbPath);\n\n// Initialize embedding model (non-blocking — FTS5 works without it)\nawait initEmbeddings();\n\n// Resolve project root for config loading\nconst __filename2 = fileURLToPath(import.meta.url);\nconst __dirname2 = dirname(__filename2);\nconst projectRoot =\n  process.env.PROJECT_ROOT || findProjectRoot(__dirname2) || process.cwd();\n\n// Initialize Turso sync (opt-in — disabled by default)\nconst syncConfig = loadSyncConfig(projectRoot);\nif (syncConfig) {\n  await initSync(dbPath, syncConfig);\n}\n\n// Register all tools (pass projectRoot for sync tools)\nregisterTools(server, db, projectRoot);\n\n// Graceful shutdown — clean up sync resources\nprocess.on(\"SIGINT\", () => {\n  shutdownSync();\n  process.exit(0);\n});\nprocess.on(\"SIGTERM\", () => {\n  shutdownSync();\n  process.exit(0);\n});\n\n// Start server\nconst transport = new StdioServerTransport();\nawait server.connect(transport);\n" });

  files.push({ path: "src/db.ts", content: "import Database from \"better-sqlite3\";\nimport * as sqliteVec from \"sqlite-vec\";\nimport { mkdirSync } from \"node:fs\";\nimport { dirname } from \"node:path\";\n\n/**\n * Initialize the SQLite database with all tables, FTS5, triggers, and indexes.\n * Uses WAL mode for concurrent read performance.\n */\nexport function initDb(dbPath: string): Database.Database {\n  // Create parent directories if needed\n  mkdirSync(dirname(dbPath), { recursive: true });\n\n  const db = new Database(dbPath);\n\n  // Performance and safety pragmas\n  db.pragma(\"journal_mode = WAL\");\n  db.pragma(\"synchronous = NORMAL\");\n  db.pragma(\"cache_size = -64000\");\n  db.pragma(\"foreign_keys = ON\");\n\n  // -- findings table --\n  db.exec(`\n    CREATE TABLE IF NOT EXISTS findings (\n      id INTEGER PRIMARY KEY AUTOINCREMENT,\n      title TEXT NOT NULL,\n      content TEXT NOT NULL,\n      type TEXT NOT NULL DEFAULT 'finding',\n      confidence TEXT DEFAULT 'medium',\n      importance REAL DEFAULT 0.4,\n      source_file TEXT,\n      source_pair TEXT,\n      tags TEXT,\n      created_at TEXT DEFAULT (datetime('now')),\n      updated_at TEXT DEFAULT (datetime('now')),\n      accessed_at TEXT DEFAULT (datetime('now')),\n      access_count INTEGER DEFAULT 0,\n      superseded_by INTEGER,  -- sentinel: -1 = archived, NULL/0 = active\n      UNIQUE(title, source_file)\n    )\n  `);\n\n  // -- pheromones table --\n  db.exec(`\n    CREATE TABLE IF NOT EXISTS pheromones (\n      id INTEGER PRIMARY KEY AUTOINCREMENT,\n      task TEXT NOT NULL,\n      pair TEXT,\n      difficulty TEXT,\n      files_touched TEXT,\n      gotchas TEXT,\n      duration_minutes INTEGER,\n      rounds INTEGER,\n      findings_count INTEGER,\n      created_at TEXT DEFAULT (datetime('now'))\n    )\n  `);\n\n  // -- FTS5 virtual table for full-text search --\n  db.exec(`\n    CREATE VIRTUAL TABLE IF NOT EXISTS findings_fts USING fts5(\n      title,\n      content,\n      tags,\n      content=findings,\n      content_rowid=id,\n      tokenize='porter unicode61 remove_diacritics 2'\n    )\n  `);\n\n  // -- FTS5 sync triggers --\n  db.exec(`\n    CREATE TRIGGER IF NOT EXISTS findings_ai AFTER INSERT ON findings BEGIN\n      INSERT INTO findings_fts(rowid, title, content, tags)\n      VALUES (new.id, new.title, new.content, new.tags);\n    END\n  `);\n\n  db.exec(`\n    CREATE TRIGGER IF NOT EXISTS findings_ad AFTER DELETE ON findings BEGIN\n      INSERT INTO findings_fts(findings_fts, rowid, title, content, tags)\n      VALUES ('delete', old.id, old.title, old.content, old.tags);\n    END\n  `);\n\n  db.exec(`\n    CREATE TRIGGER IF NOT EXISTS findings_au AFTER UPDATE ON findings BEGIN\n      INSERT INTO findings_fts(findings_fts, rowid, title, content, tags)\n      VALUES ('delete', old.id, old.title, old.content, old.tags);\n      INSERT INTO findings_fts(rowid, title, content, tags)\n      VALUES (new.id, new.title, new.content, new.tags);\n    END\n  `);\n\n  // -- Migration: add confidence_score and last_reinforced for decay engine --\n  try {\n    db.exec(`ALTER TABLE findings ADD COLUMN confidence_score REAL DEFAULT 1.0`);\n  } catch (_e) { /* column already exists */ }\n  try {\n    db.exec(`ALTER TABLE findings ADD COLUMN last_reinforced TEXT DEFAULT (datetime('now'))`);\n  } catch (_e) { /* column already exists */ }\n\n  // -- Indexes --\n  db.exec(`CREATE INDEX IF NOT EXISTS idx_findings_type ON findings(type)`);\n  db.exec(`CREATE INDEX IF NOT EXISTS idx_findings_created ON findings(created_at)`);\n  db.exec(`CREATE INDEX IF NOT EXISTS idx_findings_confidence ON findings(confidence)`);\n  db.exec(`CREATE INDEX IF NOT EXISTS idx_findings_confidence_score ON findings(confidence_score)`);\n\n  // -- sqlite-vec extension for vector search --\n  sqliteVec.load(db);\n\n  // Vector virtual table (384 dimensions for all-MiniLM-L6-v2)\n  db.exec(`\n    CREATE VIRTUAL TABLE IF NOT EXISTS findings_vec USING vec0(\n      finding_id INTEGER PRIMARY KEY,\n      embedding float[384]\n    );\n  `);\n\n  // Embedding cache — avoid re-computing embeddings for unchanged content\n  db.exec(`\n    CREATE TABLE IF NOT EXISTS embedding_cache (\n      id INTEGER PRIMARY KEY AUTOINCREMENT,\n      finding_id INTEGER UNIQUE REFERENCES findings(id) ON DELETE CASCADE,\n      content_hash TEXT NOT NULL,\n      embedding BLOB NOT NULL,\n      model TEXT DEFAULT 'all-MiniLM-L6-v2',\n      created_at TEXT DEFAULT (datetime('now'))\n    );\n  `);\n  db.exec(`CREATE INDEX IF NOT EXISTS idx_embedding_cache_hash ON embedding_cache(content_hash)`);\n\n  // -- Migration: add pheromone fields for protocol compliance --\n  try {\n    db.exec(`ALTER TABLE pheromones ADD COLUMN estimated_duration_minutes INTEGER`);\n  } catch (_e) { /* column already exists */ }\n  try {\n    db.exec(`ALTER TABLE pheromones ADD COLUMN verdict_breakdown TEXT`);\n  } catch (_e) { /* column already exists */ }\n\n  // -- contradictions table --\n  db.exec(`\n    CREATE TABLE IF NOT EXISTS contradictions (\n      id INTEGER PRIMARY KEY AUTOINCREMENT,\n      claim_a TEXT NOT NULL,\n      source_a TEXT NOT NULL,\n      claim_b TEXT NOT NULL,\n      source_b TEXT NOT NULL,\n      resolution TEXT,\n      status TEXT DEFAULT 'OPEN',\n      created_at TEXT DEFAULT (datetime('now')),\n      resolved_at TEXT\n    )\n  `);\n\n  // -- active_edits table (file claims for cross-operator coordination) --\n  db.exec(`\n    CREATE TABLE IF NOT EXISTS active_edits (\n      id INTEGER PRIMARY KEY AUTOINCREMENT,\n      operator TEXT NOT NULL,\n      pair_id TEXT NOT NULL,\n      file_path TEXT NOT NULL,\n      action TEXT,\n      status TEXT DEFAULT 'coding',\n      claimed_at TEXT DEFAULT (datetime('now')),\n      released_at TEXT,\n      UNIQUE(file_path, released_at)\n    )\n  `);\n  db.exec(`CREATE INDEX IF NOT EXISTS idx_active_edits_file ON active_edits(file_path)`);\n  db.exec(`CREATE INDEX IF NOT EXISTS idx_active_edits_pair ON active_edits(pair_id)`);\n  db.exec(`CREATE INDEX IF NOT EXISTS idx_active_edits_status ON active_edits(status)`);\n\n  // -- operators table (registered Team11 operators) --\n  db.exec(`\n    CREATE TABLE IF NOT EXISTS operators (\n      id INTEGER PRIMARY KEY AUTOINCREMENT,\n      name TEXT NOT NULL UNIQUE,\n      github TEXT,\n      prefix TEXT NOT NULL UNIQUE,\n      pairs TEXT DEFAULT '[1,2,3,4,5]',\n      registered_at TEXT DEFAULT (datetime('now')),\n      last_active TEXT DEFAULT (datetime('now'))\n    )\n  `);\n\n  // -- file_summaries table (git-aware summarization cache) --\n  db.exec(`\n    CREATE TABLE IF NOT EXISTS file_summaries (\n      id INTEGER PRIMARY KEY AUTOINCREMENT,\n      file_path TEXT NOT NULL,\n      blob_sha TEXT NOT NULL,\n      summary TEXT NOT NULL,\n      key_exports TEXT,\n      line_count INTEGER,\n      byte_size INTEGER,\n      tags TEXT,\n      generated_by TEXT DEFAULT 'agent',\n      generated_at TEXT DEFAULT (datetime('now')),\n      accessed_at TEXT DEFAULT (datetime('now')),\n      access_count INTEGER DEFAULT 0,\n      UNIQUE(file_path, blob_sha)\n    )\n  `);\n  db.exec(`CREATE INDEX IF NOT EXISTS idx_summaries_path ON file_summaries(file_path)`);\n  db.exec(`CREATE INDEX IF NOT EXISTS idx_summaries_sha ON file_summaries(blob_sha)`);\n\n  // FTS5 for summary search\n  db.exec(`\n    CREATE VIRTUAL TABLE IF NOT EXISTS summaries_fts USING fts5(\n      file_path,\n      summary,\n      key_exports,\n      tags,\n      content=file_summaries,\n      content_rowid=id,\n      tokenize='porter unicode61 remove_diacritics 2'\n    )\n  `);\n\n  // FTS5 sync triggers for summaries\n  db.exec(`\n    CREATE TRIGGER IF NOT EXISTS summaries_ai AFTER INSERT ON file_summaries BEGIN\n      INSERT INTO summaries_fts(rowid, file_path, summary, key_exports, tags)\n      VALUES (new.id, new.file_path, new.summary, new.key_exports, new.tags);\n    END\n  `);\n  db.exec(`\n    CREATE TRIGGER IF NOT EXISTS summaries_ad AFTER DELETE ON file_summaries BEGIN\n      INSERT INTO summaries_fts(summaries_fts, rowid, file_path, summary, key_exports, tags)\n      VALUES ('delete', old.id, old.file_path, old.summary, old.key_exports, old.tags);\n    END\n  `);\n  db.exec(`\n    CREATE TRIGGER IF NOT EXISTS summaries_au AFTER UPDATE ON file_summaries BEGIN\n      INSERT INTO summaries_fts(summaries_fts, rowid, file_path, summary, key_exports, tags)\n      VALUES ('delete', old.id, old.file_path, old.summary, old.key_exports, old.tags);\n      INSERT INTO summaries_fts(rowid, file_path, summary, key_exports, tags)\n      VALUES (new.id, new.file_path, new.summary, new.key_exports, new.tags);\n    END\n  `);\n\n  return db;\n}\n" });

  files.push({ path: "src/tokenize.ts", content: "/**\n * Pre-process text for FTS5 indexing.\n * Splits camelCase, PascalCase, snake_case, kebab-case, and file paths\n * into separate searchable tokens.\n */\nexport function tokenizeForFts(text: string): string {\n  return text\n    .replace(/([a-z])([A-Z])/g, \"$1 $2\")       // camelCase -> camel Case\n    .replace(/([A-Z]+)([A-Z][a-z])/g, \"$1 $2\") // HTMLParser -> HTML Parser\n    .replace(/_/g, \" \")                          // snake_case -> snake case\n    .replace(/-/g, \" \")                          // kebab-case -> kebab case\n    .replace(/[\\/\\\\.]/g, \" \")                    // file/paths -> file paths\n    .replace(/\\s+/g, \" \")                        // collapse whitespace\n    .trim();\n}\n\nconst STOPWORDS = new Set([\n  \"the\", \"a\", \"an\", \"is\", \"are\", \"was\", \"were\", \"be\", \"been\", \"being\",\n  \"have\", \"has\", \"had\", \"do\", \"does\", \"did\", \"will\", \"would\", \"could\",\n  \"should\", \"may\", \"might\", \"shall\", \"can\", \"need\", \"must\",\n  \"to\", \"of\", \"in\", \"for\", \"on\", \"with\", \"at\", \"by\", \"from\", \"as\",\n  \"into\", \"through\", \"during\", \"before\", \"after\", \"above\", \"below\",\n  \"and\", \"but\", \"or\", \"nor\", \"not\", \"so\", \"yet\", \"both\", \"either\",\n  \"neither\", \"each\", \"every\", \"all\", \"any\", \"few\", \"more\", \"most\",\n  \"other\", \"some\", \"such\", \"no\", \"only\", \"own\", \"same\",\n  \"than\", \"too\", \"very\", \"just\", \"because\", \"if\", \"when\", \"where\",\n  \"how\", \"what\", \"which\", \"who\", \"whom\", \"this\", \"that\", \"these\", \"those\",\n  \"i\", \"me\", \"my\", \"we\", \"our\", \"you\", \"your\", \"he\", \"him\", \"his\",\n  \"she\", \"her\", \"it\", \"its\", \"they\", \"them\", \"their\",\n]);\n\n/**\n * Extract search keywords from a natural language query.\n * Removes stopwords and applies tokenization.\n */\nexport function extractKeywords(text: string): string[] {\n  const tokenized = tokenizeForFts(text);\n  return tokenized\n    .toLowerCase()\n    .split(/\\s+/)\n    .filter((w) => w.length > 1 && !STOPWORDS.has(w));\n}\n\n/**\n * Build an FTS5 MATCH query from keywords.\n * Uses OR logic so partial matches still return results.\n */\nexport function buildFtsQuery(keywords: string[]): string {\n  if (keywords.length === 0) return \"\";\n  // Escape special FTS5 characters\n  const escaped = keywords.map((k) => k.replace(/['\"(){}[\\]*:^~!@#$%&]/g, \"\"));\n  return escaped.filter((k) => k.length > 0).join(\" OR \");\n}\n" });

  files.push({ path: "src/scoring.ts", content: "/**\n * Composite scoring engine for Team11 Memory MCP.\n * Formula: BM25(40%) + Importance(25%) + Recency(20%) + Access Frequency(15%)\n */\n\ninterface ScoredFields {\n  bm25_score: number;\n  importance: number;\n  updated_at?: string;\n  created_at: string;\n  access_count: number;\n  confidence_score?: number;\n}\n\n/**\n * Compute composite score for a search result.\n * All sub-scores are normalized to 0-1 before weighting.\n */\nexport function computeCompositeScore(result: ScoredFields): number {\n  // BM25: FTS5 returns negative values (lower = better match).\n  // Normalize absolute value into 0-1 range, capping at 20.\n  const bm25 = Math.min(1.0, Math.abs(result.bm25_score) / 20);\n\n  // Importance: already 0-1 in the schema, default 0.4.\n  const importance = result.importance ?? 0.4;\n\n  // Recency: 1.0 for today, linear decay to 0 over 90 days.\n  const daysSinceUpdate = daysBetween(\n    result.updated_at ?? result.created_at,\n    new Date(),\n  );\n  const recency = Math.max(0, 1.0 - daysSinceUpdate / 90);\n\n  // Access frequency: caps at 10 accesses for full score.\n  const accessFreq = Math.min((result.access_count ?? 0) / 10, 1.0);\n\n  // Confidence: multiplicative gate — low confidence entries get deprioritized.\n  const confidence = result.confidence_score ?? 1.0;\n\n  const rawScore =\n    bm25 * 0.4 + importance * 0.25 + recency * 0.2 + accessFreq * 0.15;\n  return rawScore * confidence;\n}\n\nfunction daysBetween(dateStr: string, now: Date): number {\n  const date = new Date(dateStr);\n  const ms = now.getTime() - date.getTime();\n  return Math.max(0, Math.floor(ms / (1000 * 60 * 60 * 24)));\n}\n\n/**\n * Estimate token count for a piece of text.\n * Rough approximation: 1 token ~ 4 characters.\n */\nexport function estimateTokens(text: string): number {\n  return Math.ceil(text.length / 4);\n}\n" });

  files.push({ path: "src/embeddings.ts", content: "import { pipeline, type FeatureExtractionPipeline } from \"@huggingface/transformers\";\n\n/** Canonical model name — import this instead of hardcoding the string. */\nexport const EMBEDDING_MODEL = \"all-MiniLM-L6-v2\";\n\nlet embedder: FeatureExtractionPipeline | null = null;\n\n/**\n * Initialize the embedding model. Downloads on first use (~22MB).\n * Uses all-MiniLM-L6-v2: 384-dimensional, fast, good for English text.\n */\nexport async function initEmbeddings(): Promise<void> {\n  if (embedder) return;\n  try {\n    embedder = (await pipeline(\"feature-extraction\", \"Xenova/all-MiniLM-L6-v2\")) as FeatureExtractionPipeline;\n    console.error(\"[team11-memory] Embedding model loaded: all-MiniLM-L6-v2 (384d)\");\n  } catch (err) {\n    console.error(\"[team11-memory] WARNING: Failed to load embedding model. Vector search disabled.\", err);\n    embedder = null;\n  }\n}\n\n/** Max chars per chunk — roughly MiniLM's ~256-token window. */\nconst CHUNK_SIZE = 1000;\n/** Cap chunks to bound compute on very long findings (5 * 1000 = 5000 chars). */\nconst MAX_CHUNKS = 5;\n\n/**\n * Generate embedding vector for text.\n * Returns Float32Array of 384 dimensions (for MiniLM-L6-v2).\n * Returns null if embeddings not initialized.\n *\n * Text longer than one chunk (~1000 chars) is split into sequential chunks\n * (capped at MAX_CHUNKS), each embedded separately, then mean-pooled\n * component-wise and re-normalized into a single unit vector. This preserves\n * the tail of long findings that a hard truncate would silently drop.\n * Text <= CHUNK_SIZE takes the single-embed path, identical to before.\n */\nexport async function embed(text: string): Promise<Float32Array | null> {\n  if (!embedder) return null;\n  try {\n    // Short path: single embed, unchanged behavior (no averaging artifacts).\n    if (text.length <= CHUNK_SIZE) {\n      const output = await embedder(text, { pooling: \"mean\", normalize: true });\n      return new Float32Array(output.data as Float32Array);\n    }\n\n    // Long path: chunk -> embed each -> mean-pool -> re-normalize.\n    const chunks: string[] = [];\n    for (let i = 0; i < text.length && chunks.length < MAX_CHUNKS; i += CHUNK_SIZE) {\n      chunks.push(text.substring(i, i + CHUNK_SIZE));\n    }\n\n    let pooled: Float32Array | null = null;\n    for (const chunk of chunks) {\n      const output = await embedder(chunk, { pooling: \"mean\", normalize: true });\n      const vec = output.data as Float32Array;\n      if (!pooled) {\n        pooled = new Float32Array(vec.length);\n      }\n      for (let d = 0; d < pooled.length; d++) {\n        pooled[d] += vec[d];\n      }\n    }\n    if (!pooled) return null;\n\n    // Component-wise average.\n    for (let d = 0; d < pooled.length; d++) {\n      pooled[d] /= chunks.length;\n    }\n\n    // Re-normalize to unit length (averaging unit vectors shrinks the norm).\n    let norm = 0;\n    for (let d = 0; d < pooled.length; d++) {\n      norm += pooled[d] * pooled[d];\n    }\n    norm = Math.sqrt(norm);\n    if (norm > 0) {\n      for (let d = 0; d < pooled.length; d++) {\n        pooled[d] /= norm;\n      }\n    }\n\n    return pooled;\n  } catch (err) {\n    console.error(\"[team11-memory] Embedding error:\", err);\n    return null;\n  }\n}\n\n/**\n * Check if embeddings are available.\n */\nexport function embeddingsAvailable(): boolean {\n  return embedder !== null;\n}\n\n/**\n * Get embedding dimensions.\n */\nexport function embeddingDimensions(): number {\n  return 384; // all-MiniLM-L6-v2\n}\n" });

  files.push({ path: "src/decay.ts", content: "import type Database from \"better-sqlite3\";\n\n/**\n * Confidence decay engine for Team11 Memory — v2 (2026-04-22).\n *\n * Upgrades over v1 flat 5%/week:\n * - 14-day grace period: recently-reinforced entries don't decay at all\n * - Usage-weighted: reinforce() adds +20% confidence (capped at 1.0) instead of resetting the timer\n * - Contradiction-aware: the contradictions table flags conflicts; decay does NOT overwrite\n *\n * Still below 50% => flagged stale. Below 25% => archived (superseded_by = -1).\n */\n\nconst DECAY_RATE = 0.05; // 5% per week after grace period\nconst STALE_THRESHOLD = 0.5; // Flag at 50%\nconst ARCHIVE_THRESHOLD = 0.25; // Archive at 25%\nconst GRACE_PERIOD_DAYS = 14; // Entries touched within N days don't decay\nconst REINFORCE_BUMP = 0.2; // Each reinforcement adds 20% (capped at 1.0)\n\nexport interface DecayResult {\n  updated: number;\n  flagged: number;\n  archived: number;\n  skipped_grace: number;\n  flaggedEntries: Array<{ id: number; title: string; confidence: number }>;\n  archivedEntries: Array<{ id: number; title: string; confidence: number }>;\n}\n\n/**\n * Calculate current confidence based on time since last reinforcement.\n *\n * - Within GRACE_PERIOD_DAYS of last_reinforced: no decay (returns null).\n * - After grace: exponential decay at DECAY_RATE per week measured from the\n *   grace-period boundary, not from last_reinforced itself.\n *\n * Returns null if the entry is in grace period (caller preserves existing confidence).\n */\nexport function calculateConfidence(\n  lastReinforced: string,\n  currentConfidence: number,\n): number | null {\n  const now = new Date();\n  const reinforced = new Date(lastReinforced);\n  const daysSince =\n    (now.getTime() - reinforced.getTime()) / (1000 * 60 * 60 * 24);\n  if (daysSince < GRACE_PERIOD_DAYS) {\n    return null; // Grace — do not decay\n  }\n  const weeksAfterGrace = (daysSince - GRACE_PERIOD_DAYS) / 7;\n  const decayed = currentConfidence * Math.pow(1 - DECAY_RATE, weeksAfterGrace);\n  return Math.max(0, decayed);\n}\n\n/**\n * Run confidence decay across all active findings.\n *\n * Respects the 14-day grace period — recently-reinforced entries are skipped.\n * Only decays entries that have been untouched for >= GRACE_PERIOD_DAYS.\n */\nexport function runDecay(db: Database.Database): DecayResult {\n  const findings = db\n    .prepare(\n      `SELECT id, title, type, confidence_score, last_reinforced, created_at, superseded_by\n       FROM findings\n       WHERE superseded_by IS NULL OR superseded_by = 0`,\n    )\n    .all() as any[];\n\n  let updated = 0;\n  let flagged = 0;\n  let archived = 0;\n  let skipped_grace = 0;\n  const flaggedEntries: DecayResult[\"flaggedEntries\"] = [];\n  const archivedEntries: DecayResult[\"archivedEntries\"] = [];\n\n  const updateStmt = db.prepare(\n    `UPDATE findings SET confidence_score = ? WHERE id = ?`,\n  );\n  const archiveStmt = db.prepare(\n    `UPDATE findings SET superseded_by = -1 WHERE id = ?`,\n  );\n\n  for (const f of findings) {\n    const currentConfidence = f.confidence_score ?? 1.0;\n    const newConfidence = calculateConfidence(\n      f.last_reinforced || f.created_at,\n      currentConfidence,\n    );\n    if (newConfidence === null) {\n      skipped_grace++;\n      continue; // Still in grace period — don't touch\n    }\n    if (Math.abs(newConfidence - currentConfidence) > 0.01) {\n      updateStmt.run(newConfidence, f.id);\n      updated++;\n    }\n    if (newConfidence < ARCHIVE_THRESHOLD && f.superseded_by !== -1) {\n      archiveStmt.run(f.id);\n      archived++;\n      archivedEntries.push({\n        id: f.id,\n        title: f.title,\n        confidence: newConfidence,\n      });\n    } else if (newConfidence < STALE_THRESHOLD) {\n      flagged++;\n      flaggedEntries.push({\n        id: f.id,\n        title: f.title,\n        confidence: newConfidence,\n      });\n    }\n  }\n\n  return { updated, flagged, archived, skipped_grace, flaggedEntries, archivedEntries };\n}\n\n/**\n * Reinforce a finding.\n *\n * Adds REINFORCE_BUMP (20%) to current confidence, capped at 1.0.\n * Resets last_reinforced to now — entry re-enters grace period.\n *\n * Called when an agent re-confirms a fact (via [REINFORCED] marker) OR\n * when memory tools like recall_context/search_memory return the entry\n * (usage-weighted reinforcement — access IS confirmation).\n */\nexport function reinforce(db: Database.Database, findingId: number): void {\n  db.prepare(\n    `UPDATE findings SET\n       confidence_score = MIN(1.0, COALESCE(confidence_score, 0.5) + ?),\n       last_reinforced = datetime('now'),\n       updated_at = datetime('now')\n     WHERE id = ?`,\n  ).run(REINFORCE_BUMP, findingId);\n}\n\n/**\n * Touch a finding on read — lighter than full reinforce.\n *\n * Used by recall_context / search_memory / get_file_summary when they\n * return an entry. Updates last_reinforced so the entry re-enters grace\n * period, but does NOT bump confidence_score — read access is a weaker\n * signal than an explicit [REINFORCED] marker.\n */\nexport function touchOnRead(db: Database.Database, findingId: number): void {\n  db.prepare(\n    `UPDATE findings SET\n       last_reinforced = datetime('now'),\n       updated_at = datetime('now')\n     WHERE id = ?`,\n  ).run(findingId);\n}\n\n/**\n * Bulk touch — same as touchOnRead but for a list of ids in one transaction.\n * Tools returning multiple entries should use this.\n */\nexport function touchManyOnRead(\n  db: Database.Database,\n  findingIds: number[],\n): void {\n  if (findingIds.length === 0) return;\n  const stmt = db.prepare(`UPDATE findings SET\n       last_reinforced = datetime('now'),\n       updated_at = datetime('now')\n     WHERE id = ?`);\n  const txn = db.transaction((ids: number[]) => {\n    for (const id of ids) stmt.run(id);\n  });\n  txn(findingIds);\n}\n\n/**\n * Restore an archived finding (un-archive).\n * Resets confidence to 1.0 and clears the archive marker.\n */\nexport function restore(db: Database.Database, findingId: number): void {\n  db.prepare(\n    `UPDATE findings SET\n       superseded_by = NULL,\n       confidence_score = 1.0,\n       last_reinforced = datetime('now'),\n       updated_at = datetime('now')\n     WHERE id = ?`,\n  ).run(findingId);\n}\n\n/**\n * Garbage-collect stale file summaries.\n * Deletes entries not generated or accessed in the last 7 days.\n */\nexport function gcSummaries(db: Database.Database): { deleted: number } {\n  const result = db.prepare(`\n    DELETE FROM file_summaries\n    WHERE generated_at < datetime('now', '-7 days')\n      AND accessed_at < datetime('now', '-7 days')\n  `).run();\n  return { deleted: result.changes };\n}\n" });

  files.push({ path: "src/sync.ts", content: "import { createClient, type Client } from \"@libsql/client\";\nimport { existsSync, readFileSync } from \"node:fs\";\nimport { join } from \"node:path\";\n\nexport interface SyncConfig {\n  enabled: boolean;\n  provider: \"turso\";\n  url: string;\n  token: string;\n  syncInterval?: number;\n}\n\nlet syncClient: Client | null = null;\nlet syncTimer: ReturnType<typeof setInterval> | null = null;\n\n/**\n * Load sync config from .team11/config.json.\n * Returns null if sync is disabled or config is missing/invalid.\n */\nexport function loadSyncConfig(projectRoot: string): SyncConfig | null {\n  const configPath = join(projectRoot, \".team11\", \"config.json\");\n  if (!existsSync(configPath)) return null;\n\n  try {\n    const config = JSON.parse(readFileSync(configPath, \"utf8\"));\n    if (!config.sync || !config.sync.enabled) return null;\n    const syncConfig = config.sync as SyncConfig;\n    // Allow env var override for token (more secure than config file)\n    if (!syncConfig.token && process.env.TURSO_AUTH_TOKEN) {\n      syncConfig.token = process.env.TURSO_AUTH_TOKEN;\n    }\n    return syncConfig;\n  } catch {\n    return null;\n  }\n}\n\n/**\n * Initialize Turso embedded replica.\n *\n * Uses @libsql/client in embedded replica mode: a local SQLite file that\n * syncs to a Turso cloud primary. better-sqlite3 continues to handle all\n * reads/writes against the same file; this client only drives sync().\n *\n * Returns the Client on success, null on failure (local-only fallback).\n */\nexport async function initSync(\n  dbPath: string,\n  syncConfig: SyncConfig,\n): Promise<Client | null> {\n  if (!syncConfig.enabled || !syncConfig.url || !syncConfig.token) {\n    console.error(\n      \"[team11-memory] Sync disabled or incomplete config. Running local-only.\",\n    );\n    return null;\n  }\n\n  try {\n    syncClient = createClient({\n      url: `file:${dbPath}`,\n      syncUrl: syncConfig.url,\n      authToken: syncConfig.token,\n    });\n\n    // Initial sync -- pull remote state\n    await syncClient.sync();\n    console.error(`[team11-memory] Turso sync connected: ${syncConfig.url}`);\n    console.error(\n      `[team11-memory] Sync interval: ${syncConfig.syncInterval || 60}s`,\n    );\n\n    // Periodic background sync\n    const intervalMs = (syncConfig.syncInterval || 60) * 1000;\n    syncTimer = setInterval(async () => {\n      try {\n        await syncClient?.sync();\n      } catch (err) {\n        console.error(\"[team11-memory] Sync error (will retry):\", err);\n      }\n    }, intervalMs);\n\n    return syncClient;\n  } catch (err) {\n    console.error(\n      \"[team11-memory] Failed to initialize Turso sync. Running local-only.\",\n      err,\n    );\n    syncClient = null;\n    return null;\n  }\n}\n\n/**\n * Force an immediate sync (call after writes to push changes promptly).\n */\nexport async function forceSync(): Promise<void> {\n  if (!syncClient) return;\n  try {\n    await syncClient.sync();\n  } catch (err) {\n    console.error(\"[team11-memory] Force sync failed:\", err);\n  }\n}\n\n/**\n * Shut down sync cleanly -- clear the timer and close the client.\n */\nexport function shutdownSync(): void {\n  if (syncTimer) {\n    clearInterval(syncTimer);\n    syncTimer = null;\n  }\n  if (syncClient) {\n    syncClient.close();\n    syncClient = null;\n  }\n}\n\n/**\n * Check whether Turso sync is currently active.\n */\nexport function isSyncActive(): boolean {\n  return syncClient !== null;\n}\n" });

  files.push({ path: "src/tools/index.ts", content: "import type { McpServer } from \"@modelcontextprotocol/sdk/server/mcp.js\";\nimport type Database from \"better-sqlite3\";\nimport { registerRecallTools } from \"./recall.js\";\nimport { registerStoreTools } from \"./store.js\";\nimport { registerSearchTools } from \"./search.js\";\nimport { registerPheromoneTools } from \"./pheromones.js\";\nimport { registerSyncTools } from \"./sync.js\";\nimport { registerSummaryTools } from \"./summaries.js\";\nimport { registerContradictionTools } from \"./contradictions.js\";\nimport { registerHealthTools } from \"./health.js\";\nimport { registerCoordinationTools } from \"./coordination.js\";\n\nexport function registerTools(\n  server: McpServer,\n  db: Database.Database,\n  projectRoot: string,\n): void {\n  registerRecallTools(server, db);\n  registerStoreTools(server, db);\n  registerSearchTools(server, db);\n  registerPheromoneTools(server, db, projectRoot);\n  registerSyncTools(server, projectRoot);\n  registerSummaryTools(server, db, projectRoot);\n  registerContradictionTools(server, db);\n  registerCoordinationTools(server, db);\n\n  // health_check is registered last so it can report the total tool count.\n  // Count: recall(2) + store(3) + search(7) + pheromones(2) + sync(2) +\n  //        summaries(2) + contradictions(3) + coordination(6) + health(1) = 28\n  const TOOL_COUNT = 28;\n  registerHealthTools(server, db, TOOL_COUNT);\n}\n" });

  files.push({ path: "src/tools/recall.ts", content: "import type { McpServer } from \"@modelcontextprotocol/sdk/server/mcp.js\";\nimport type Database from \"better-sqlite3\";\nimport { z } from \"zod\";\nimport { computeCompositeScore, estimateTokens } from \"../scoring.js\";\nimport { extractKeywords, buildFtsQuery } from \"../tokenize.js\";\nimport { embed, embeddingsAvailable } from \"../embeddings.js\";\n\nexport function registerRecallTools(\n  server: McpServer,\n  db: Database.Database,\n): void {\n  // recall_context — primary retrieval tool\n  server.tool(\n    \"recall_context\",\n    \"Retrieve relevant context for a task from Team11's persistent memory. Returns findings, decisions, gotchas, and pheromone data ranked by relevance.\",\n    {\n      task_description: z\n        .string()\n        .describe(\"Natural language description of the task\"),\n      max_tokens: z\n        .number()\n        .optional()\n        .default(8000)\n        .describe(\"Maximum tokens in response\"),\n    },\n    async ({ task_description, max_tokens }) => {\n      const keywords = extractKeywords(task_description);\n      if (keywords.length === 0) {\n        return {\n          content: [\n            {\n              type: \"text\" as const,\n              text: JSON.stringify({\n                query: task_description,\n                results_count: 0,\n                findings: [],\n                decisions: [],\n                gotchas: [],\n                facts: [],\n                pheromones: [],\n              }),\n            },\n          ],\n        };\n      }\n\n      const ftsQuery = buildFtsQuery(keywords);\n\n      // FTS5 search with BM25 scoring — weights: title(10), content(1), tags(2)\n      // Excludes archived entries (superseded_by = -1 is the archive marker)\n      const ftsResults = db\n        .prepare(\n          `\n        SELECT f.*, bm25(findings_fts, 10.0, 1.0, 2.0) as bm25_score\n        FROM findings_fts fts\n        JOIN findings f ON f.id = fts.rowid\n        WHERE findings_fts MATCH ?\n          AND (f.superseded_by IS NULL OR f.superseded_by = 0)\n        ORDER BY bm25(findings_fts, 10.0, 1.0, 2.0)\n        LIMIT 50\n      `,\n        )\n        .all(ftsQuery);\n\n      // Vector search (if embeddings are available)\n      let vectorResults: any[] = [];\n      if (embeddingsAvailable()) {\n        const queryVector = await embed(task_description);\n        if (queryVector) {\n          const vectorBlob = Buffer.from(queryVector.buffer);\n          vectorResults = db\n            .prepare(\n              `\n            SELECT f.*, v.distance\n            FROM findings_vec v\n            JOIN findings f ON f.id = v.finding_id\n            WHERE v.embedding MATCH ? AND k = 30\n            ORDER BY v.distance\n          `,\n            )\n            .all(vectorBlob);\n        }\n      }\n\n      // Merge results via Reciprocal Rank Fusion (RRF)\n      // Then apply composite scoring as secondary sort within RRF groups\n      const merged = mergeWithRRF(ftsResults, vectorResults);\n      const scored = merged.map((r: any) => ({\n        ...r,\n        composite_score: computeCompositeScore({\n          ...r,\n          bm25_score: r.bm25_score ?? 0,\n        }),\n      }));\n      // Final sort: RRF score primary, composite secondary\n      scored.sort((a: any, b: any) => {\n        const rrfDiff = (b.rrf_score ?? 0) - (a.rrf_score ?? 0);\n        if (Math.abs(rrfDiff) > 0.001) return rrfDiff;\n        return b.composite_score - a.composite_score;\n      });\n\n      // Token budget enforcement — reserve 500 tokens for envelope\n      let tokenBudget = max_tokens - 500;\n      const included: any[] = [];\n      for (const r of scored) {\n        const est = estimateTokens(r.title + r.content);\n        if (tokenBudget - est < 0) break;\n        tokenBudget -= est;\n        included.push(r);\n\n        // Update access tracking + usage-weighted decay: access IS reinforcement.\n        // Bumping last_reinforced re-enters the 14-day grace period (see decay.ts).\n        db.prepare(\n          `UPDATE findings SET\n             accessed_at = datetime('now'),\n             access_count = access_count + 1,\n             last_reinforced = datetime('now')\n           WHERE id = ?`,\n        ).run(r.id);\n      }\n\n      // Pheromone lookup by keyword match\n      const pheromonePattern = `%${keywords.join(\"%\")}%`;\n      const pheromones = db\n        .prepare(\n          `\n        SELECT * FROM pheromones\n        WHERE task LIKE ? OR files_touched LIKE ? OR gotchas LIKE ?\n        ORDER BY created_at DESC LIMIT 10\n      `,\n        )\n        .all(pheromonePattern, pheromonePattern, pheromonePattern);\n\n      const response = {\n        query: task_description,\n        results_count: included.length,\n        token_estimate: max_tokens - tokenBudget,\n        findings: included\n          .filter((r: any) => r.type === \"finding\")\n          .map(summarize),\n        decisions: included\n          .filter((r: any) => r.type === \"decision\")\n          .map(summarize),\n        gotchas: included\n          .filter((r: any) => r.type === \"gotcha\")\n          .map(summarize),\n        facts: included\n          .filter((r: any) => r.type === \"fact\")\n          .map(summarize),\n        pheromones: pheromones.map((p: any) => ({\n          task: p.task,\n          difficulty: p.difficulty,\n          files: safeJsonParse(p.files_touched, []),\n          gotchas: safeJsonParse(p.gotchas, []),\n          duration_minutes: p.duration_minutes,\n        })),\n      };\n\n      return {\n        content: [\n          { type: \"text\" as const, text: JSON.stringify(response, null, 2) },\n        ],\n      };\n    },\n  );\n\n  // get_detail — fetch full content by ID\n  server.tool(\n    \"get_detail\",\n    \"Get the full content of a specific memory entry by ID. Use after recall_context returns summaries.\",\n    {\n      id: z.number().describe(\"The finding/decision/gotcha ID\"),\n    },\n    async ({ id }) => {\n      const result = db\n        .prepare(`SELECT * FROM findings WHERE id = ?`)\n        .get(id) as Record<string, unknown> | undefined;\n      if (!result) {\n        return {\n          content: [\n            {\n              type: \"text\" as const,\n              text: JSON.stringify({ error: \"Not found\" }),\n            },\n          ],\n        };\n      }\n      // Update access tracking + usage-weighted decay.\n      db.prepare(\n        `UPDATE findings SET\n           accessed_at = datetime('now'),\n           access_count = access_count + 1,\n           last_reinforced = datetime('now')\n         WHERE id = ?`,\n      ).run(id);\n      return {\n        content: [\n          { type: \"text\" as const, text: JSON.stringify(result, null, 2) },\n        ],\n      };\n    },\n  );\n}\n\nfunction summarize(r: any) {\n  return {\n    id: r.id,\n    title: r.title,\n    type: r.type,\n    confidence: r.confidence,\n    score: Math.round(r.composite_score * 100) / 100,\n    created_at: r.created_at,\n    summary:\n      r.content.length > 200\n        ? r.content.substring(0, 200) + \"...\"\n        : r.content,\n  };\n}\n\nfunction safeJsonParse(str: string | null, fallback: any): any {\n  if (!str) return fallback;\n  try {\n    return JSON.parse(str);\n  } catch {\n    return fallback;\n  }\n}\n\n/**\n * Reciprocal Rank Fusion (RRF) to merge FTS5 + vector search results.\n * RRF score = sum(1 / (k + rank)) across both result sets.\n * k = 60 is the standard constant.\n */\nfunction mergeWithRRF(ftsResults: any[], vecResults: any[], k: number = 60): any[] {\n  const scores = new Map<number, { item: any; score: number }>();\n\n  ftsResults.forEach((item, rank) => {\n    const existing = scores.get(item.id) || { item, score: 0 };\n    existing.score += 1 / (k + rank);\n    if (!scores.has(item.id)) existing.item = item;\n    scores.set(item.id, existing);\n  });\n\n  vecResults.forEach((item, rank) => {\n    const existing = scores.get(item.id) || { item, score: 0 };\n    existing.score += 1 / (k + rank);\n    if (!scores.has(item.id)) existing.item = item;\n    scores.set(item.id, existing);\n  });\n\n  return Array.from(scores.values())\n    .sort((a, b) => b.score - a.score)\n    .map(({ item, score }) => ({ ...item, rrf_score: score }));\n}\n" });

  files.push({ path: "src/tools/store.ts", content: "import type { McpServer } from \"@modelcontextprotocol/sdk/server/mcp.js\";\nimport type Database from \"better-sqlite3\";\nimport { z } from \"zod\";\nimport { createHash } from \"node:crypto\";\nimport { embed, embeddingsAvailable } from \"../embeddings.js\";\nimport { forceSync, isSyncActive } from \"../sync.js\";\n\n/**\n * Generate and store embedding for a finding.\n * Skips if embeddings unavailable or content unchanged (by hash).\n */\nasync function storeEmbedding(db: Database.Database, findingId: number | bigint, content: string): Promise<void> {\n  if (!embeddingsAvailable()) return;\n\n  const contentHash = createHash(\"sha256\").update(content).digest(\"hex\");\n\n  // Check cache — skip if content unchanged\n  const cached = db.prepare(`SELECT content_hash FROM embedding_cache WHERE finding_id = ?`).get(Number(findingId)) as { content_hash: string } | undefined;\n  if (cached && cached.content_hash === contentHash) return;\n\n  const vector = await embed(content);\n  if (!vector) return;\n\n  const vectorBlob = Buffer.from(vector.buffer);\n\n  // Store in vec0 virtual table\n  db.prepare(`INSERT OR REPLACE INTO findings_vec (finding_id, embedding) VALUES (CAST(? AS INTEGER), ?)`).run(Number(findingId), vectorBlob);\n\n  // Store in cache\n  db.prepare(`INSERT OR REPLACE INTO embedding_cache (finding_id, content_hash, embedding) VALUES (?, ?, ?)`).run(Number(findingId), contentHash, vectorBlob);\n}\n\nexport function registerStoreTools(\n  server: McpServer,\n  db: Database.Database,\n): void {\n  server.tool(\n    \"store_finding\",\n    \"Store a finding, decision, gotcha, or fact in Team11's persistent memory.\",\n    {\n      title: z.string().describe(\"Short title for the finding\"),\n      content: z.string().describe(\"Full content/description\"),\n      type: z\n        .enum([\"finding\", \"decision\", \"gotcha\", \"fact\", \"architecture\"])\n        .default(\"finding\"),\n      confidence: z\n        .enum([\"high\", \"medium\", \"low\"])\n        .optional()\n        .default(\"medium\"),\n      importance: z\n        .number()\n        .min(0)\n        .max(1)\n        .optional()\n        .default(0.4),\n      source_pair: z\n        .string()\n        .optional()\n        .describe(\"Which pair created this\"),\n      source_file: z\n        .string()\n        .optional()\n        .describe(\"Original source file path\"),\n      tags: z\n        .array(z.string())\n        .optional()\n        .describe(\"Tags for categorization\"),\n    },\n    async ({\n      title,\n      content,\n      type,\n      confidence,\n      importance,\n      source_pair,\n      source_file,\n      tags,\n    }) => {\n      const tagsJson = tags ? JSON.stringify(tags) : null;\n\n      const result = db\n        .prepare(\n          `\n        INSERT INTO findings (title, content, type, confidence, importance, source_pair, source_file, tags)\n        VALUES (?, ?, ?, ?, ?, ?, ?, ?)\n      `,\n        )\n        .run(\n          title,\n          content,\n          type,\n          confidence,\n          importance,\n          source_pair ?? null,\n          source_file ?? null,\n          tagsJson,\n        );\n\n      await storeEmbedding(db, result.lastInsertRowid, `${title} ${content}`);\n      if (isSyncActive()) await forceSync();\n\n      return {\n        content: [\n          {\n            type: \"text\" as const,\n            text: JSON.stringify({\n              stored: true,\n              id: result.lastInsertRowid,\n              type,\n            }),\n          },\n        ],\n      };\n    },\n  );\n\n  server.tool(\n    \"store_decision\",\n    \"Store an architectural or design decision with rationale.\",\n    {\n      title: z.string().describe(\"Decision title\"),\n      content: z.string().describe(\"What was decided\"),\n      rationale: z.string().describe(\"Why this was decided\"),\n      decided_by: z.string().optional().default(\"Human\"),\n      tags: z.array(z.string()).optional(),\n    },\n    async ({ title, content, rationale, decided_by, tags }) => {\n      const fullContent = `${content}\\n\\nRationale: ${rationale}\\nDecided by: ${decided_by}`;\n      const tagsJson = tags ? JSON.stringify(tags) : null;\n\n      const result = db\n        .prepare(\n          `\n        INSERT INTO findings (title, content, type, confidence, importance, tags)\n        VALUES (?, ?, 'decision', 'high', 0.8, ?)\n      `,\n        )\n        .run(title, fullContent, tagsJson);\n\n      await storeEmbedding(db, result.lastInsertRowid, `${title} ${fullContent}`);\n      if (isSyncActive()) await forceSync();\n\n      return {\n        content: [\n          {\n            type: \"text\" as const,\n            text: JSON.stringify({\n              stored: true,\n              id: result.lastInsertRowid,\n              type: \"decision\",\n            }),\n          },\n        ],\n      };\n    },\n  );\n\n  server.tool(\n    \"store_gotcha\",\n    \"Store a gotcha or non-obvious pitfall for future agents to avoid.\",\n    {\n      title: z.string().describe(\"Brief gotcha description\"),\n      content: z\n        .string()\n        .describe(\"Full explanation with file paths and evidence\"),\n      evidence: z\n        .string()\n        .optional()\n        .describe(\"How this was discovered\"),\n      tags: z.array(z.string()).optional(),\n    },\n    async ({ title, content, evidence, tags }) => {\n      const fullContent = evidence\n        ? `${content}\\n\\nEvidence: ${evidence}`\n        : content;\n      const tagsJson = tags ? JSON.stringify(tags) : null;\n\n      const result = db\n        .prepare(\n          `\n        INSERT INTO findings (title, content, type, confidence, importance, tags)\n        VALUES (?, ?, 'gotcha', 'high', 0.7, ?)\n      `,\n        )\n        .run(title, fullContent, tagsJson);\n\n      await storeEmbedding(db, result.lastInsertRowid, `${title} ${fullContent}`);\n      if (isSyncActive()) await forceSync();\n\n      return {\n        content: [\n          {\n            type: \"text\" as const,\n            text: JSON.stringify({\n              stored: true,\n              id: result.lastInsertRowid,\n              type: \"gotcha\",\n            }),\n          },\n        ],\n      };\n    },\n  );\n}\n\n// Re-export for use by seed script\nexport { storeEmbedding };\n" });

  files.push({ path: "src/tools/search.ts", content: "import type { McpServer } from \"@modelcontextprotocol/sdk/server/mcp.js\";\nimport type Database from \"better-sqlite3\";\nimport { z } from \"zod\";\nimport { extractKeywords, buildFtsQuery } from \"../tokenize.js\";\nimport { runDecay, reinforce, restore, touchManyOnRead } from \"../decay.js\";\n\nexport function registerSearchTools(\n  server: McpServer,\n  db: Database.Database,\n): void {\n  server.tool(\n    \"search_memory\",\n    \"Search Team11's persistent memory with a free-text query. Returns matching entries ranked by relevance.\",\n    {\n      query: z\n        .string()\n        .describe(\n          'Search query (supports AND, OR, NOT, \"phrases\", prefix*)',\n        ),\n      type_filter: z\n        .enum([\n          \"finding\",\n          \"decision\",\n          \"gotcha\",\n          \"fact\",\n          \"architecture\",\n          \"all\",\n        ])\n        .optional()\n        .default(\"all\"),\n      limit: z.number().optional().default(20),\n    },\n    async ({ query, type_filter, limit }) => {\n      const keywords = extractKeywords(query);\n      if (keywords.length === 0) {\n        return {\n          content: [\n            {\n              type: \"text\" as const,\n              text: JSON.stringify({ results: [], count: 0 }),\n            },\n          ],\n        };\n      }\n\n      const ftsQuery = buildFtsQuery(keywords);\n      let sql = `\n        SELECT f.*, bm25(findings_fts, 10.0, 1.0, 2.0) as relevance\n        FROM findings_fts fts\n        JOIN findings f ON f.id = fts.rowid\n        WHERE findings_fts MATCH ?\n      `;\n      const params: any[] = [ftsQuery];\n\n      if (type_filter && type_filter !== \"all\") {\n        sql += ` AND f.type = ?`;\n        params.push(type_filter);\n      }\n\n      sql += ` ORDER BY relevance LIMIT ?`;\n      params.push(limit);\n\n      const results = db.prepare(sql).all(...params) as Array<{ id: number }>;\n\n      // Usage-weighted decay: touching returned entries bumps last_reinforced\n      // so they re-enter the 14-day grace period (see decay.ts).\n      touchManyOnRead(db, results.map((r) => r.id));\n\n      return {\n        content: [\n          {\n            type: \"text\" as const,\n            text: JSON.stringify({ results, count: results.length }),\n          },\n        ],\n      };\n    },\n  );\n\n  server.tool(\n    \"list_recent\",\n    \"List the most recent memory entries, optionally filtered by type.\",\n    {\n      type_filter: z\n        .enum([\n          \"finding\",\n          \"decision\",\n          \"gotcha\",\n          \"fact\",\n          \"architecture\",\n          \"all\",\n        ])\n        .optional()\n        .default(\"all\"),\n      limit: z.number().optional().default(20),\n      days: z\n        .number()\n        .optional()\n        .default(30)\n        .describe(\"Only show entries from the last N days\"),\n    },\n    async ({ type_filter, limit, days }) => {\n      let sql = `SELECT * FROM findings WHERE created_at >= datetime('now', ?)`;\n      const params: any[] = [`-${days} days`];\n\n      if (type_filter && type_filter !== \"all\") {\n        sql += ` AND type = ?`;\n        params.push(type_filter);\n      }\n\n      sql += ` ORDER BY created_at DESC LIMIT ?`;\n      params.push(limit);\n\n      const results = db.prepare(sql).all(...params);\n      return {\n        content: [\n          {\n            type: \"text\" as const,\n            text: JSON.stringify({ results, count: results.length }),\n          },\n        ],\n      };\n    },\n  );\n\n  server.tool(\n    \"memory_stats\",\n    \"Show statistics about Team11's persistent memory database.\",\n    {},\n    async () => {\n      const stats = {\n        total: db\n          .prepare(`SELECT COUNT(*) as count FROM findings`)\n          .get(),\n        by_type: db\n          .prepare(\n            `SELECT type, COUNT(*) as count FROM findings GROUP BY type`,\n          )\n          .all(),\n        by_confidence: db\n          .prepare(\n            `SELECT confidence, COUNT(*) as count FROM findings GROUP BY confidence`,\n          )\n          .all(),\n        recent_7d: db\n          .prepare(\n            `SELECT COUNT(*) as count FROM findings WHERE created_at >= datetime('now', '-7 days')`,\n          )\n          .get(),\n        pheromones: db\n          .prepare(`SELECT COUNT(*) as count FROM pheromones`)\n          .get(),\n        oldest: db\n          .prepare(\n            `SELECT created_at FROM findings ORDER BY created_at ASC LIMIT 1`,\n          )\n          .get(),\n        newest: db\n          .prepare(\n            `SELECT created_at FROM findings ORDER BY created_at DESC LIMIT 1`,\n          )\n          .get(),\n      };\n      return {\n        content: [\n          { type: \"text\" as const, text: JSON.stringify(stats, null, 2) },\n        ],\n      };\n    },\n  );\n\n  // -- Confidence decay tools --\n\n  server.tool(\n    \"run_decay\",\n    \"Run confidence decay across all memory entries. Updates scores based on time since last reinforcement. Flags stale entries (<50%) and archives very stale ones (<25%).\",\n    {},\n    async () => {\n      const result = runDecay(db);\n      return {\n        content: [\n          { type: \"text\" as const, text: JSON.stringify(result, null, 2) },\n        ],\n      };\n    },\n  );\n\n  server.tool(\n    \"reinforce_finding\",\n    \"Reinforce a finding — reset its confidence decay timer. Use when an agent re-confirms a fact is still true.\",\n    {\n      id: z.number().describe(\"Finding ID to reinforce\"),\n    },\n    async ({ id }) => {\n      reinforce(db, id);\n      return {\n        content: [\n          {\n            type: \"text\" as const,\n            text: JSON.stringify({ reinforced: true, id }),\n          },\n        ],\n      };\n    },\n  );\n\n  server.tool(\n    \"restore_finding\",\n    \"Restore an archived finding. Un-archives it and resets confidence to 1.0.\",\n    {\n      id: z.number().describe(\"Finding ID to restore\"),\n    },\n    async ({ id }) => {\n      restore(db, id);\n      return {\n        content: [\n          {\n            type: \"text\" as const,\n            text: JSON.stringify({ restored: true, id }),\n          },\n        ],\n      };\n    },\n  );\n\n  server.tool(\n    \"list_stale\",\n    \"List findings with low confidence scores that may need re-verification or archival.\",\n    {\n      threshold: z\n        .number()\n        .optional()\n        .default(0.5)\n        .describe(\"Confidence threshold (default 0.5)\"),\n      include_archived: z.boolean().optional().default(false),\n    },\n    async ({ threshold, include_archived }) => {\n      let sql = `SELECT id, title, type, confidence_score, last_reinforced, created_at FROM findings WHERE confidence_score < ?`;\n      if (!include_archived) {\n        sql += ` AND (superseded_by IS NULL OR superseded_by = 0)`;\n      }\n      sql += ` ORDER BY confidence_score ASC`;\n\n      const results = db.prepare(sql).all(threshold);\n      return {\n        content: [\n          {\n            type: \"text\" as const,\n            text: JSON.stringify(\n              { stale: results, count: results.length },\n              null,\n              2,\n            ),\n          },\n        ],\n      };\n    },\n  );\n}\n" });

  files.push({ path: "src/tools/pheromones.ts", content: "import type { McpServer } from \"@modelcontextprotocol/sdk/server/mcp.js\";\nimport type Database from \"better-sqlite3\";\nimport { z } from \"zod\";\nimport { forceSync, isSyncActive } from \"../sync.js\";\nimport { existsSync, readFileSync, writeFileSync } from \"node:fs\";\nimport { join } from \"node:path\";\n\nexport function registerPheromoneTools(\n  server: McpServer,\n  db: Database.Database,\n  projectRoot: string,\n): void {\n  server.tool(\n    \"store_pheromone\",\n    \"Store a pheromone trail after completing a task. Helps future agents estimate difficulty and avoid gotchas.\",\n    {\n      task: z.string().describe(\"Task description\"),\n      pair: z.string().optional(),\n      difficulty: z.enum([\"LOW\", \"MEDIUM\", \"HIGH\"]),\n      files_touched: z\n        .array(z.string())\n        .describe(\"List of files modified\"),\n      gotchas: z\n        .array(z.string())\n        .optional()\n        .describe(\"Non-obvious issues encountered\"),\n      duration_minutes: z.number().optional(),\n      estimated_duration_minutes: z.number().optional().describe(\"Estimated duration before starting\"),\n      rounds: z\n        .number()\n        .optional()\n        .describe(\"Number of code-audit rounds\"),\n      findings_count: z.number().optional(),\n      verdict_breakdown: z.object({\n        confirmed: z.number(),\n        disputed: z.number(),\n        deferred: z.number(),\n      }).optional().describe(\"Verdict counts from audit\"),\n    },\n    async ({\n      task,\n      pair,\n      difficulty,\n      files_touched,\n      gotchas,\n      duration_minutes,\n      estimated_duration_minutes,\n      rounds,\n      findings_count,\n      verdict_breakdown,\n    }) => {\n      const result = db\n        .prepare(\n          `\n        INSERT INTO pheromones (task, pair, difficulty, files_touched, gotchas, duration_minutes, estimated_duration_minutes, rounds, findings_count, verdict_breakdown)\n        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)\n      `,\n        )\n        .run(\n          task,\n          pair ?? null,\n          difficulty,\n          JSON.stringify(files_touched),\n          JSON.stringify(gotchas ?? []),\n          duration_minutes ?? null,\n          estimated_duration_minutes ?? null,\n          rounds ?? null,\n          findings_count ?? null,\n          verdict_breakdown ? JSON.stringify(verdict_breakdown) : null,\n        );\n\n      // Dual-write to pheromones.json\n      const pheromonePath = join(projectRoot, \".team11\", \"pheromones.json\");\n      try {\n        const existing = existsSync(pheromonePath)\n          ? JSON.parse(readFileSync(pheromonePath, \"utf8\"))\n          : { trails: [] };\n        existing.trails.push({\n          date: new Date().toISOString().split(\"T\")[0],\n          pair: pair ?? null,\n          task,\n          difficulty,\n          files: files_touched,\n          gotchas: gotchas ?? [],\n          estimated_duration_min: estimated_duration_minutes ?? null,\n          actual_duration_min: duration_minutes ?? null,\n          rounds: rounds ?? null,\n          findings_count: findings_count ?? null,\n          verdict_breakdown: verdict_breakdown ?? null,\n        });\n        writeFileSync(pheromonePath, JSON.stringify(existing, null, 2));\n      } catch (err) {\n        console.error(\"[team11-memory] Warning: Failed to write pheromones.json:\", err);\n      }\n\n      if (isSyncActive()) await forceSync();\n\n      return {\n        content: [\n          {\n            type: \"text\" as const,\n            text: JSON.stringify({\n              stored: true,\n              id: result.lastInsertRowid,\n            }),\n          },\n        ],\n      };\n    },\n  );\n\n  server.tool(\n    \"get_pheromones\",\n    \"Get pheromone trail data for files or tasks. Shows what happened last time someone worked on these files.\",\n    {\n      files: z\n        .array(z.string())\n        .optional()\n        .describe(\"File paths to check pheromone data for\"),\n      task_keywords: z\n        .string()\n        .optional()\n        .describe(\"Keywords to search pheromone tasks\"),\n      limit: z.number().optional().default(10),\n    },\n    async ({ files, task_keywords, limit }) => {\n      let results: any[] = [];\n\n      if (files && files.length > 0) {\n        const placeholders = files\n          .map(() => `files_touched LIKE ?`)\n          .join(\" OR \");\n        const params = files.map((f) => `%${f}%`);\n        results = db\n          .prepare(\n            `SELECT * FROM pheromones WHERE ${placeholders} ORDER BY created_at DESC LIMIT ?`,\n          )\n          .all(...params, limit);\n      } else if (task_keywords) {\n        results = db\n          .prepare(\n            `SELECT * FROM pheromones WHERE task LIKE ? ORDER BY created_at DESC LIMIT ?`,\n          )\n          .all(`%${task_keywords}%`, limit);\n      } else {\n        results = db\n          .prepare(\n            `SELECT * FROM pheromones ORDER BY created_at DESC LIMIT ?`,\n          )\n          .all(limit);\n      }\n\n      const parsed = results.map((r: any) => ({\n        ...r,\n        files_touched: safeJsonParse(r.files_touched, []),\n        gotchas: safeJsonParse(r.gotchas, []),\n        verdict_breakdown: safeJsonParse(r.verdict_breakdown, null),\n      }));\n\n      return {\n        content: [\n          {\n            type: \"text\" as const,\n            text: JSON.stringify({\n              pheromones: parsed,\n              count: parsed.length,\n            }),\n          },\n        ],\n      };\n    },\n  );\n}\n\nfunction safeJsonParse(str: string | null, fallback: any): any {\n  if (!str) return fallback;\n  try {\n    return JSON.parse(str);\n  } catch {\n    return fallback;\n  }\n}\n" });

  files.push({ path: "src/tools/sync.ts", content: "import type { McpServer } from \"@modelcontextprotocol/sdk/server/mcp.js\";\nimport {\n  loadSyncConfig,\n  forceSync,\n  isSyncActive,\n} from \"../sync.js\";\n\nexport function registerSyncTools(\n  server: McpServer,\n  projectRoot: string,\n): void {\n  server.tool(\n    \"sync_status\",\n    \"Check the status of Turso sync. Returns whether sync is active and connection details.\",\n    {},\n    async () => {\n      const config = loadSyncConfig(projectRoot);\n      return {\n        content: [\n          {\n            type: \"text\" as const,\n            text: JSON.stringify({\n              sync_enabled: isSyncActive(),\n              provider: config?.provider || \"none\",\n              url: config?.url || \"local-only\",\n              interval_seconds: config?.syncInterval || 60,\n            }),\n          },\n        ],\n      };\n    },\n  );\n\n  server.tool(\n    \"force_sync\",\n    \"Force an immediate sync with the Turso cloud. Use after batch operations.\",\n    {},\n    async () => {\n      if (!isSyncActive()) {\n        return {\n          content: [\n            {\n              type: \"text\" as const,\n              text: JSON.stringify({\n                error:\n                  \"Sync not active. Configure sync in .team11/config.json\",\n              }),\n            },\n          ],\n        };\n      }\n      await forceSync();\n      return {\n        content: [\n          {\n            type: \"text\" as const,\n            text: JSON.stringify({ synced: true }),\n          },\n        ],\n      };\n    },\n  );\n}\n" });

  files.push({ path: "src/tools/summaries.ts", content: "import type { McpServer } from \"@modelcontextprotocol/sdk/server/mcp.js\";\nimport type Database from \"better-sqlite3\";\nimport { z } from \"zod\";\nimport { execFileSync } from \"node:child_process\";\nimport { createHash } from \"node:crypto\";\nimport { readFileSync, statSync } from \"node:fs\";\nimport { resolve } from \"node:path\";\nimport { forceSync, isSyncActive } from \"../sync.js\";\n\n/**\n * Compute the blob SHA for a file, matching git's content-addressable storage.\n * Uses `git hash-object` for tracked files; falls back to sha256 for untracked/dirty.\n */\nfunction computeBlobSha(filePath: string, projectRoot: string): string {\n  const absPath = resolve(projectRoot, filePath);\n  try {\n    // Try git hash-object first (works for tracked files).\n    // execFileSync (no shell) — absPath is passed as an argv element, so a\n    // malicious file_path cannot inject shell metacharacters (D1: RCE fix).\n    const sha = execFileSync(\"git\", [\"hash-object\", absPath], {\n      cwd: projectRoot,\n      encoding: \"utf8\",\n      timeout: 5000,\n    }).trim();\n    if (sha) return sha;\n  } catch {\n    // Fall through to content hash\n  }\n  // Fallback: sha256 of file content (for untracked/dirty files)\n  const content = readFileSync(absPath);\n  return createHash(\"sha256\").update(content).digest(\"hex\");\n}\n\ninterface SummaryRow {\n  id: number;\n  file_path: string;\n  blob_sha: string;\n  summary: string;\n  key_exports: string | null;\n  line_count: number | null;\n  byte_size: number | null;\n  tags: string | null;\n  generated_by: string;\n  generated_at: string;\n  accessed_at: string;\n  access_count: number;\n}\n\nexport function registerSummaryTools(\n  server: McpServer,\n  db: Database.Database,\n  projectRoot: string,\n): void {\n  server.tool(\n    \"get_file_summary\",\n    \"Get a cached structural summary for a file. Returns the summary if the file content (by git blob SHA) hasn't changed, or {cached: false} if the file needs a fresh read.\",\n    {\n      file_path: z\n        .string()\n        .describe(\"Relative path from project root (e.g. 'client-game/src/main.js')\"),\n      project_root: z\n        .string()\n        .optional()\n        .describe(\"Override project root (defaults to server's project root)\"),\n    },\n    async ({ file_path, project_root }) => {\n      const root = project_root ?? projectRoot;\n\n      // Verify file exists before hashing\n      const absPath = resolve(root, file_path);\n      try {\n        statSync(absPath);\n      } catch {\n        return {\n          content: [\n            {\n              type: \"text\" as const,\n              text: JSON.stringify({\n                cached: false,\n                error: \"file_not_found\",\n                file_path,\n              }),\n            },\n          ],\n        };\n      }\n\n      const blobSha = computeBlobSha(file_path, root);\n\n      const row = db\n        .prepare(\n          `SELECT * FROM file_summaries WHERE file_path = ? AND blob_sha = ?`,\n        )\n        .get(file_path, blobSha) as SummaryRow | undefined;\n\n      if (!row) {\n        return {\n          content: [\n            {\n              type: \"text\" as const,\n              text: JSON.stringify({\n                cached: false,\n                file_path,\n                blob_sha: blobSha,\n              }),\n            },\n          ],\n        };\n      }\n\n      // Update access tracking\n      db.prepare(\n        `UPDATE file_summaries\n         SET accessed_at = datetime('now'),\n             access_count = access_count + 1\n         WHERE id = ?`,\n      ).run(row.id);\n\n      return {\n        content: [\n          {\n            type: \"text\" as const,\n            text: JSON.stringify({\n              cached: true,\n              file_path: row.file_path,\n              blob_sha: row.blob_sha,\n              summary: row.summary,\n              key_exports: row.key_exports ? JSON.parse(row.key_exports) : null,\n              line_count: row.line_count,\n              byte_size: row.byte_size,\n              tags: row.tags ? JSON.parse(row.tags) : null,\n              generated_at: row.generated_at,\n              access_count: row.access_count + 1,\n            }),\n          },\n        ],\n      };\n    },\n  );\n\n  server.tool(\n    \"store_file_summary\",\n    \"Store a structural summary for a file, keyed by its current git blob SHA. Upserts on (file_path, blob_sha) — safe to call repeatedly.\",\n    {\n      file_path: z\n        .string()\n        .describe(\"Relative path from project root\"),\n      summary: z\n        .string()\n        .describe(\"Structural summary of the file (~400 tokens)\"),\n      key_exports: z\n        .array(z.string())\n        .optional()\n        .describe(\"Exported functions, classes, constants\"),\n      line_count: z.number().optional().describe(\"Number of lines in the file\"),\n      byte_size: z.number().optional().describe(\"File size in bytes\"),\n      tags: z\n        .array(z.string())\n        .optional()\n        .describe(\"Tags for categorization (e.g. 'ui', 'network', 'server')\"),\n      project_root: z\n        .string()\n        .optional()\n        .describe(\"Override project root (defaults to server's project root)\"),\n    },\n    async ({ file_path, summary, key_exports, line_count, byte_size, tags, project_root }) => {\n      const root = project_root ?? projectRoot;\n      const blobSha = computeBlobSha(file_path, root);\n      const keyExportsJson = key_exports ? JSON.stringify(key_exports) : null;\n      const tagsJson = tags ? JSON.stringify(tags) : null;\n\n      const result = db\n        .prepare(\n          `INSERT INTO file_summaries (file_path, blob_sha, summary, key_exports, line_count, byte_size, tags)\n           VALUES (?, ?, ?, ?, ?, ?, ?)\n           ON CONFLICT(file_path, blob_sha) DO UPDATE SET\n             summary = excluded.summary,\n             key_exports = excluded.key_exports,\n             line_count = excluded.line_count,\n             byte_size = excluded.byte_size,\n             tags = excluded.tags,\n             generated_at = datetime('now'),\n             accessed_at = datetime('now')`,\n        )\n        .run(file_path, blobSha, summary, keyExportsJson, line_count ?? null, byte_size ?? null, tagsJson);\n\n      if (isSyncActive()) await forceSync();\n\n      return {\n        content: [\n          {\n            type: \"text\" as const,\n            text: JSON.stringify({\n              stored: true,\n              file_path,\n              blob_sha: blobSha,\n              id: result.lastInsertRowid,\n            }),\n          },\n        ],\n      };\n    },\n  );\n}\n" });

  files.push({ path: "src/tools/contradictions.ts", content: "import type { McpServer } from \"@modelcontextprotocol/sdk/server/mcp.js\";\nimport type Database from \"better-sqlite3\";\nimport { z } from \"zod\";\nimport { forceSync, isSyncActive } from \"../sync.js\";\n\nexport function registerContradictionTools(\n  server: McpServer,\n  db: Database.Database,\n): void {\n  server.tool(\n    \"store_contradiction\",\n    \"Store a contradiction between two claims discovered by agents.\",\n    {\n      claim_a: z.string().describe(\"First claim\"),\n      source_a: z.string().describe(\"Source of first claim (e.g., Pair 1, F001)\"),\n      claim_b: z.string().describe(\"Contradicting claim\"),\n      source_b: z.string().describe(\"Source of contradicting claim\"),\n      resolution: z.string().optional().describe(\"How it was resolved, if known\"),\n      status: z.enum([\"OPEN\", \"RESOLVED\", \"DEFERRED\"]).optional().default(\"OPEN\"),\n    },\n    async ({ claim_a, source_a, claim_b, source_b, resolution, status }) => {\n      const result = db.prepare(`\n        INSERT INTO contradictions (claim_a, source_a, claim_b, source_b, resolution, status)\n        VALUES (?, ?, ?, ?, ?, ?)\n      `).run(claim_a, source_a, claim_b, source_b, resolution ?? null, status);\n      if (isSyncActive()) await forceSync();\n      return {\n        content: [{\n          type: \"text\" as const,\n          text: JSON.stringify({ stored: true, id: result.lastInsertRowid, status }),\n        }],\n      };\n    },\n  );\n\n  server.tool(\n    \"resolve_contradiction\",\n    \"Resolve a previously stored contradiction.\",\n    {\n      id: z.number().describe(\"Contradiction ID\"),\n      resolution: z.string().describe(\"How it was resolved\"),\n      status: z.enum([\"RESOLVED\", \"DEFERRED\"]).default(\"RESOLVED\"),\n    },\n    async ({ id, resolution, status }) => {\n      db.prepare(`\n        UPDATE contradictions SET resolution = ?, status = ?, resolved_at = datetime('now') WHERE id = ?\n      `).run(resolution, status, id);\n      if (isSyncActive()) await forceSync();\n      return {\n        content: [{ type: \"text\" as const, text: JSON.stringify({ updated: true, id, status }) }],\n      };\n    },\n  );\n\n  server.tool(\n    \"list_contradictions\",\n    \"List contradictions, optionally filtered by status.\",\n    {\n      status: z.enum([\"OPEN\", \"RESOLVED\", \"DEFERRED\", \"ALL\"]).optional().default(\"OPEN\"),\n      limit: z.number().optional().default(20),\n    },\n    async ({ status, limit }) => {\n      const results = status === \"ALL\"\n        ? db.prepare(`SELECT * FROM contradictions ORDER BY created_at DESC LIMIT ?`).all(limit)\n        : db.prepare(`SELECT * FROM contradictions WHERE status = ? ORDER BY created_at DESC LIMIT ?`).all(status, limit);\n      return {\n        content: [{ type: \"text\" as const, text: JSON.stringify({ contradictions: results, count: results.length }) }],\n      };\n    },\n  );\n}\n" });

  files.push({ path: "src/tools/health.ts", content: "import { statSync } from \"node:fs\";\nimport type { McpServer } from \"@modelcontextprotocol/sdk/server/mcp.js\";\nimport type Database from \"better-sqlite3\";\nimport { isSyncActive } from \"../sync.js\";\nimport { embeddingsAvailable, embeddingDimensions, EMBEDDING_MODEL } from \"../embeddings.js\";\n\n/**\n * Register the health_check tool.\n * Returns database counts, sync status, embedding availability,\n * and the number of tools registered on the server.\n */\nexport function registerHealthTools(\n  server: McpServer,\n  db: Database.Database,\n  toolCount: number,\n): void {\n  server.tool(\n    \"health_check\",\n    \"Return server health: DB table counts, sync status, embedding availability, and registered tool count.\",\n    {},\n    async () => {\n      // Safe query helper — returns -1 on failure so the response degrades\n      // instead of crashing the entire tool.\n      const safeQuery = (): Record<string, number> | null => {\n        try {\n          return db.prepare(`\n            SELECT\n              (SELECT COUNT(*) FROM findings) as findings,\n              (SELECT COUNT(*) FROM pheromones) as pheromones,\n              (SELECT COUNT(*) FROM contradictions) as contradictions,\n              (SELECT COUNT(*) FROM file_summaries) as summaries,\n              (SELECT COUNT(*) FROM findings WHERE superseded_by = -1) as archived\n          `).get() as Record<string, number>;\n        } catch {\n          return null;\n        }\n      };\n\n      try {\n        const counts = safeQuery();\n\n        const syncActive = isSyncActive();\n\n        const result = {\n          db: {\n            findings_count: counts?.findings ?? -1,\n            pheromones_count: counts?.pheromones ?? -1,\n            contradictions_count: counts?.contradictions ?? -1,\n            file_summaries_count: counts?.summaries ?? -1,\n            archived_count: counts?.archived ?? -1,\n            // statSync is intentional — entire handler uses synchronous better-sqlite3 queries\n            size_bytes: (() => {\n              try {\n                const mainSize = statSync(db.name).size;\n                let totalSize = mainSize;\n                try { totalSize += statSync(db.name + '-wal').size; } catch { /* no WAL file */ }\n                try { totalSize += statSync(db.name + '-shm').size; } catch { /* no SHM file */ }\n                return totalSize;\n              } catch { return -1; }\n            })(),\n          },\n          sync: {\n            active: syncActive,\n            provider: syncActive ? (\"turso\" as const) : null,\n          },\n          embeddings: {\n            available: embeddingsAvailable(),\n            model: EMBEDDING_MODEL,\n            dimensions: embeddingDimensions(),\n          },\n          tools_registered: toolCount,\n        };\n\n        return {\n          content: [\n            {\n              type: \"text\" as const,\n              text: JSON.stringify(result, null, 2),\n            },\n          ],\n        };\n      } catch (err: unknown) {\n        const msg = err instanceof Error ? err.message : String(err);\n        return {\n          content: [\n            {\n              type: \"text\" as const,\n              text: JSON.stringify({ error: \"health_check_failed\", details: msg }, null, 2),\n            },\n          ],\n        };\n      }\n    },\n  );\n}\n" });

  files.push({ path: "src/tools/coordination.ts", content: "import type { McpServer } from \"@modelcontextprotocol/sdk/server/mcp.js\";\nimport type Database from \"better-sqlite3\";\nimport { z } from \"zod\";\nimport { forceSync, isSyncActive } from \"../sync.js\";\n\nexport function registerCoordinationTools(\n  server: McpServer,\n  db: Database.Database,\n): void {\n  server.tool(\n    \"claim_file\",\n    \"Claim a file for editing. Returns conflict info if already claimed by another pair.\",\n    {\n      operator: z.string().describe(\"Operator name (e.g., CyberStein)\"),\n      pair_id: z.string().describe(\"Pair ID (e.g., cs-pair-1)\"),\n      file_path: z.string().describe(\"File path to claim\"),\n      action: z.string().optional().describe(\"What the pair intends to do with the file\"),\n    },\n    async ({ operator, pair_id, file_path, action }) => {\n      const existing = db.prepare(`\n        SELECT id, operator, pair_id, action, status, claimed_at\n        FROM active_edits\n        WHERE file_path = ? AND released_at IS NULL\n      `).get(file_path) as { id: number; operator: string; pair_id: string; action: string | null; status: string; claimed_at: string } | undefined;\n\n      if (existing && existing.pair_id !== pair_id) {\n        return {\n          content: [{\n            type: \"text\" as const,\n            text: JSON.stringify({\n              claimed: false,\n              held_by: existing.pair_id,\n              held_by_operator: existing.operator,\n              action: existing.action,\n              since: existing.claimed_at,\n            }),\n          }],\n        };\n      }\n\n      if (existing && existing.pair_id === pair_id) {\n        return {\n          content: [{\n            type: \"text\" as const,\n            text: JSON.stringify({\n              claimed: true,\n              id: existing.id,\n              note: \"Already claimed by this pair\",\n            }),\n          }],\n        };\n      }\n\n      const result = db.prepare(`\n        INSERT INTO active_edits (operator, pair_id, file_path, action)\n        VALUES (?, ?, ?, ?)\n      `).run(operator, pair_id, file_path, action ?? null);\n\n      if (isSyncActive()) await forceSync();\n\n      return {\n        content: [{\n          type: \"text\" as const,\n          text: JSON.stringify({ claimed: true, id: result.lastInsertRowid }),\n        }],\n      };\n    },\n  );\n\n  server.tool(\n    \"release_file\",\n    \"Release all file claims for a pair (typically after merge).\",\n    {\n      pair_id: z.string().describe(\"Pair ID whose claims to release\"),\n    },\n    async ({ pair_id }) => {\n      const result = db.prepare(`\n        UPDATE active_edits\n        SET released_at = datetime('now'), status = 'merged'\n        WHERE pair_id = ? AND released_at IS NULL\n      `).run(pair_id);\n\n      if (isSyncActive()) await forceSync();\n\n      return {\n        content: [{\n          type: \"text\" as const,\n          text: JSON.stringify({ released: true, files_released: result.changes }),\n        }],\n      };\n    },\n  );\n\n  server.tool(\n    \"list_active_edits\",\n    \"List all currently claimed files, optionally filtered by operator.\",\n    {\n      operator: z.string().optional().describe(\"Filter by operator name\"),\n    },\n    async ({ operator }) => {\n      const results = operator\n        ? db.prepare(`SELECT * FROM active_edits WHERE released_at IS NULL AND operator = ? ORDER BY claimed_at DESC`).all(operator)\n        : db.prepare(`SELECT * FROM active_edits WHERE released_at IS NULL ORDER BY claimed_at DESC`).all();\n\n      return {\n        content: [{\n          type: \"text\" as const,\n          text: JSON.stringify({ active_edits: results, count: results.length }),\n        }],\n      };\n    },\n  );\n\n  server.tool(\n    \"register_operator\",\n    \"Register a new Team11 operator or update an existing one.\",\n    {\n      name: z.string().describe(\"Operator name\"),\n      github: z.string().optional().describe(\"GitHub username\"),\n      prefix: z.string().describe(\"Short prefix for pair IDs (e.g., cs)\"),\n      pairs: z.string().optional().describe(\"JSON array of pair numbers (default: [1,2,3,4,5])\"),\n    },\n    async ({ name, github, prefix, pairs }) => {\n      db.prepare(`\n        INSERT INTO operators (name, github, prefix, pairs)\n        VALUES (?, ?, ?, ?)\n        ON CONFLICT(name) DO UPDATE SET\n          github = excluded.github,\n          prefix = excluded.prefix,\n          pairs = excluded.pairs,\n          last_active = datetime('now')\n      `).run(name, github ?? null, prefix, pairs ?? \"[1,2,3,4,5]\");\n\n      if (isSyncActive()) await forceSync();\n\n      return {\n        content: [{\n          type: \"text\" as const,\n          text: JSON.stringify({ registered: true, name, prefix }),\n        }],\n      };\n    },\n  );\n\n  server.tool(\n    \"list_operators\",\n    \"List all registered Team11 operators.\",\n    {},\n    async () => {\n      const results = db.prepare(`SELECT * FROM operators ORDER BY last_active DESC`).all();\n\n      return {\n        content: [{\n          type: \"text\" as const,\n          text: JSON.stringify({ operators: results, count: results.length }),\n        }],\n      };\n    },\n  );\n\n  server.tool(\n    \"heartbeat_operator\",\n    \"Update an operator's last_active timestamp.\",\n    {\n      name: z.string().describe(\"Operator name\"),\n    },\n    async ({ name }) => {\n      const result = db.prepare(`\n        UPDATE operators SET last_active = datetime('now') WHERE name = ?\n      `).run(name);\n\n      if (isSyncActive()) await forceSync();\n\n      return {\n        content: [{\n          type: \"text\" as const,\n          text: JSON.stringify({\n            updated: result.changes > 0,\n            name,\n            note: result.changes === 0 ? \"Operator not found\" : undefined,\n          }),\n        }],\n      };\n    },\n  );\n}\n" });

  files.push({ path: "src/scripts/seed.ts", content: "import Database from \"better-sqlite3\";\nimport { readdirSync, readFileSync, existsSync, mkdirSync } from \"fs\";\nimport { join, dirname } from \"path\";\nimport { fileURLToPath } from \"url\";\nimport { createHash } from \"crypto\";\nimport { initEmbeddings, embed, embeddingsAvailable } from \"../embeddings.js\";\n\nconst __dirname = dirname(fileURLToPath(import.meta.url));\n\n// Find project root (go up from .team11/mcp-server/dist/scripts/)\nfunction findProjectRoot(): string {\n  // If TEAM11_DIR env var is set, use its parent\n  if (process.env.TEAM11_DIR) {\n    return dirname(process.env.TEAM11_DIR);\n  }\n  // Otherwise walk up from script location\n  let dir = __dirname;\n  for (let i = 0; i < 10; i++) {\n    if (existsSync(join(dir, '.team11'))) return dir;\n    dir = dirname(dir);\n  }\n  throw new Error(\"Could not find project root (no .team11/ directory found)\");\n}\n\nconst projectRoot = findProjectRoot();\nconst team11Dir = join(projectRoot, \".team11\");\nconst dbPath = join(team11Dir, \"memory.db\");\n\nconsole.log(`Seeding Team11 memory database at: ${dbPath}`);\nconsole.log(`Reading findings from: ${join(team11Dir, \"findings\")}`);\n\n// Import initDb from our db module\n// Since we're running from dist/, import relatively\nimport { initDb } from \"../db.js\";\n\nconst db = initDb(dbPath);\n\n// Parse a finding .md file\nfunction parseFindingMd(content: string, filePath: string) {\n  const title = content.match(/^#\\s+(.+)/m)?.[1] || filePath;\n  const type = content.match(/\\*\\*Type:\\*\\*\\s+(.+)/)?.[1]?.trim() || \"finding\";\n  const date = content.match(/\\*\\*Date:\\*\\*\\s+(.+)/)?.[1]?.trim();\n  const author = content.match(/\\*\\*Author:\\*\\*\\s+(.+)/)?.[1]?.trim();\n  const confidence = content.match(/\\*\\*Confidence:\\*\\*\\s+(.+)/)?.[1]?.trim() || \"medium\";\n\n  // Get content (everything after the header block, before Sources)\n  const sections = content.split(/^## /m).slice(1);\n  const mainContent = sections\n    .filter(s => !s.startsWith(\"Sources\"))\n    .map(s => s.trim())\n    .join(\"\\n\\n## \");\n\n  return {\n    title: title.replace(/^#+\\s*/, ''),\n    content: mainContent || content,\n    type: mapType(type),\n    confidence: mapConfidence(confidence),\n    source_file: filePath,\n    source_pair: author || null,\n    created_at: date || new Date().toISOString().split('T')[0],\n  };\n}\n\nfunction mapType(raw: string): string {\n  const lower = raw.toLowerCase();\n  if (lower.includes('decision')) return 'decision';\n  if (lower.includes('gotcha')) return 'gotcha';\n  if (lower.includes('fact')) return 'fact';\n  if (lower.includes('architecture')) return 'architecture';\n  return 'finding';\n}\n\nfunction mapConfidence(raw: string): string {\n  const lower = raw.toLowerCase();\n  if (lower.includes('high')) return 'high';\n  if (lower.includes('low')) return 'low';\n  return 'medium';\n}\n\n// Initialize embedding model before seeding\nawait initEmbeddings();\n\n// Seed findings\nconst findingsDir = join(team11Dir, \"findings\");\nif (existsSync(findingsDir)) {\n  const files = readdirSync(findingsDir).filter(f => f.endsWith('.md'));\n  console.log(`Found ${files.length} finding files`);\n\n  const insertStmt = db.prepare(`\n    INSERT OR IGNORE INTO findings (title, content, type, confidence, source_file, source_pair, created_at)\n    VALUES (?, ?, ?, ?, ?, ?, ?)\n  `);\n\n  let count = 0;\n  for (const file of files) {\n    const content = readFileSync(join(findingsDir, file), \"utf8\");\n    const parsed = parseFindingMd(content, file);\n\n    try {\n      insertStmt.run(\n        parsed.title,\n        parsed.content,\n        parsed.type,\n        parsed.confidence,\n        parsed.source_file,\n        parsed.source_pair,\n        parsed.created_at\n      );\n      count++;\n      console.log(`  Seeded: ${parsed.title} (${parsed.type})`);\n    } catch (err: any) {\n      console.error(`  Error seeding ${file}: ${err.message}`);\n    }\n  }\n\n  console.log(`\\nSeeded ${count} findings into memory.db`);\n} else {\n  console.log(\"No findings directory found, skipping\");\n}\n\n// Generate embeddings for all findings that don't have one yet\nif (embeddingsAvailable()) {\n  const allFindings = db.prepare(`SELECT id, title, content FROM findings`).all() as { id: number; title: string; content: string }[];\n  let embeddedCount = 0;\n  for (const finding of allFindings) {\n    const text = `${finding.title} ${finding.content}`;\n    const contentHash = createHash(\"sha256\").update(text).digest(\"hex\");\n\n    // Skip if already cached with same hash\n    const cached = db.prepare(`SELECT content_hash FROM embedding_cache WHERE finding_id = ?`).get(finding.id) as { content_hash: string } | undefined;\n    if (cached && cached.content_hash === contentHash) continue;\n\n    const vector = await embed(text);\n    if (!vector) continue;\n\n    const vectorBlob = Buffer.from(vector.buffer);\n    const findingId = Number(finding.id);\n    db.prepare(`INSERT OR REPLACE INTO findings_vec (finding_id, embedding) VALUES (CAST(? AS INTEGER), ?)`).run(findingId, vectorBlob);\n    db.prepare(`INSERT OR REPLACE INTO embedding_cache (finding_id, content_hash, embedding) VALUES (?, ?, ?)`).run(findingId, contentHash, vectorBlob);\n    embeddedCount++;\n  }\n  console.log(`Generated embeddings for ${embeddedCount} findings`);\n} else {\n  console.log(\"Embeddings not available, skipping vector indexing\");\n}\n\n// Seed pheromones from pheromones.json\nconst pheromonesPath = join(team11Dir, \"pheromones.json\");\nif (existsSync(pheromonesPath)) {\n  const data = JSON.parse(readFileSync(pheromonesPath, \"utf8\"));\n  if (data.trails && data.trails.length > 0) {\n    const insertPheromone = db.prepare(`\n      INSERT OR IGNORE INTO pheromones (task, pair, difficulty, files_touched, gotchas, duration_minutes, rounds, findings_count, created_at)\n      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)\n    `);\n\n    let count = 0;\n    for (const trail of data.trails) {\n      try {\n        insertPheromone.run(\n          trail.task,\n          trail.pair ? String(trail.pair) : null,\n          trail.difficulty || 'MEDIUM',\n          JSON.stringify(trail.files || []),\n          JSON.stringify(trail.gotchas || []),\n          trail.duration_minutes || trail.actual_duration_min || null,\n          trail.rounds || null,\n          trail.findings_count || null,\n          trail.date || new Date().toISOString().split('T')[0]\n        );\n        count++;\n      } catch (err: any) {\n        console.error(`  Error seeding pheromone: ${err.message}`);\n      }\n    }\n    console.log(`Seeded ${count} pheromone trails`);\n  }\n} else {\n  console.log(\"No pheromones.json found, skipping\");\n}\n\n// Print stats\nconst total = db.prepare(`SELECT COUNT(*) as count FROM findings`).get() as any;\nconst byType = db.prepare(`SELECT type, COUNT(*) as count FROM findings GROUP BY type`).all();\nconst pheromoneCount = db.prepare(`SELECT COUNT(*) as count FROM pheromones`).get() as any;\n\nconsole.log(`\\n--- Memory DB Stats ---`);\nconsole.log(`Total findings: ${total.count}`);\nfor (const t of byType) {\n  console.log(`  ${(t as any).type}: ${(t as any).count}`);\n}\nconsole.log(`Pheromone trails: ${pheromoneCount.count}`);\nconsole.log(`Database: ${dbPath}`);\n\ndb.close();\n" });

  files.push({ path: "src/scripts/bootstrap.ts", content: "/**\n * bootstrap.ts — Run from inside a project's .team11/mcp-server/ to get everything working.\n *\n * Usage: cd <project>/.team11/mcp-server && node dist/scripts/bootstrap.js\n *\n * Checks what's missing and fixes it:\n *   - node_modules missing? → npm install\n *   - dist/ missing? → npm run build\n *   - memory.db missing or tables missing? → initDb()\n *   - config.json missing? → creates solo default\n *   - pheromones.json missing? → creates empty\n *   - hive.md missing? → creates default\n *   - .gitignore missing Team11 entries? → adds them\n *   - .mcp.json missing team11-memory? → adds it\n *\n * Safe to run repeatedly — skips anything already done.\n */\n\nimport { existsSync, mkdirSync, writeFileSync, readFileSync } from \"node:fs\";\nimport { join, dirname, resolve } from \"node:path\";\nimport { fileURLToPath } from \"node:url\";\nimport { execSync } from \"node:child_process\";\nimport { initDb } from \"../db.js\";\n\nconst __dirname = dirname(fileURLToPath(import.meta.url));\n\nfunction findProjectRoot(): string {\n  let dir = __dirname;\n  for (let i = 0; i < 10; i++) {\n    if (existsSync(join(dir, \".team11\"))) return dir;\n    dir = dirname(dir);\n  }\n  // Fallback: assume we're in .team11/mcp-server/dist/scripts/\n  return resolve(__dirname, \"..\", \"..\", \"..\", \"..\");\n}\n\nfunction main() {\n  const projectRoot = findProjectRoot();\n  const team11Dir = join(projectRoot, \".team11\");\n  const mcpDir = join(team11Dir, \"mcp-server\");\n  const projectName = projectRoot.split(/[\\\\/]/).pop() || \"project\";\n\n  console.log(`\\nTeam11 Bootstrap — ${projectName}`);\n  console.log(`Project: ${projectRoot}\\n`);\n\n  let fixes = 0;\n\n  // 1. State directories\n  for (const d of [\"logs\", \"findings\", \"checkpoints\", \"stale\", \"inboxes\", \"proposals\"]) {\n    const p = join(team11Dir, d);\n    if (!existsSync(p)) { mkdirSync(p, { recursive: true }); fixes++; }\n  }\n  console.log(`[1/7] State directories: OK`);\n\n  // 2. config.json\n  const configPath = join(team11Dir, \"config.json\");\n  if (!existsSync(configPath)) {\n    writeFileSync(configPath, JSON.stringify({\n      mode: \"solo\",\n      operator: null,\n      repo: null,\n      pre_verification: { enabled: false, commands: [] }\n    }, null, 2));\n    console.log(`[2/7] config.json: CREATED (solo mode)`);\n    fixes++;\n  } else {\n    console.log(`[2/7] config.json: OK`);\n  }\n\n  // 3. Database\n  const dbPath = join(team11Dir, \"memory.db\");\n  try {\n    const db = initDb(dbPath);\n    const tables = (db.prepare(\"SELECT COUNT(*) as c FROM sqlite_master WHERE type='table'\").get() as {c: number}).c;\n    db.close();\n    console.log(`[3/7] Database: OK (${tables} tables)`);\n    if (!existsSync(dbPath.replace(\"memory.db\", \"\") + \"memory.db\")) fixes++; // new DB\n  } catch (err: any) {\n    console.log(`[3/7] Database: ERROR — ${err.message}`);\n  }\n\n  // 4. pheromones.json\n  const pheroPath = join(team11Dir, \"pheromones.json\");\n  if (!existsSync(pheroPath)) {\n    writeFileSync(pheroPath, JSON.stringify({ trails: [] }, null, 2));\n    console.log(`[4/7] pheromones.json: CREATED`);\n    fixes++;\n  } else {\n    console.log(`[4/7] pheromones.json: OK`);\n  }\n\n  // 5. hive.md\n  const hivePath = join(team11Dir, \"hive.md\");\n  if (!existsSync(hivePath)) {\n    const date = new Date().toISOString().split(\"T\")[0];\n    writeFileSync(hivePath, `# Hive Mind\n**Project:** ${projectName}\n**Date:** ${date}\n**Type:** hive-mind\n**Version:** 1\n\n## Active Edits\n| Pair | Agent | File | Action | Status | Timestamp |\n|------|-------|------|--------|--------|-----------|\n\n## Discovered Facts\n| ID | Fact | Source | Confidence | Last Reinforced | Timestamp |\n|----|------|--------|------------|-----------------|-----------|\n\n## Decisions\n| ID | Decision | Rationale | Decided By | Timestamp |\n|----|----------|-----------|------------|-----------|\n\n## Contradictions\n| ID | Claim A | Source A | Claim B | Source B | Resolution | Status |\n|----|---------|----------|---------|----------|------------|--------|\n\n## Pheromone Trails\n| Date | Pair | Task | Difficulty | Files Touched | Gotchas | Duration |\n|------|------|------|------------|---------------|---------|----------|\n`);\n    console.log(`[5/7] hive.md: CREATED`);\n    fixes++;\n  } else {\n    console.log(`[5/7] hive.md: OK`);\n  }\n\n  // 6. .gitignore\n  const gitignorePath = join(projectRoot, \".gitignore\");\n  const gitignore = existsSync(gitignorePath) ? readFileSync(gitignorePath, \"utf8\") : \"\";\n  if (!gitignore.includes(\".team11/config.json\")) {\n    const block = `\n# Team11 state (ephemeral)\n.team11/config.json\n.team11/memory.db\n.team11/memory.db-*\n.team11/knowledge-graph.jsonl\n.team11/logs/\n.team11/findings/\n.team11/checkpoints/\n.team11/stale/\n.team11/inboxes/\n.team11/proposals/\n.team11/hive.md\n.team11/pheromones.json\n.team11/_outbox.json\n.team11/mcp-server/dist/\n.team11/mcp-server/node_modules/\n!.team11/mcp-server/\n!.team11/mcp-server/src/\n!.team11/mcp-server/src/**\n!.team11/mcp-server/package.json\n!.team11/mcp-server/package-lock.json\n!.team11/mcp-server/tsconfig.json\n!.team11/mcp-server/README.md\n`;\n    let updated = gitignore.replace(/^\\.team11\\/\\s*$/m, \"\");\n    updated = updated.trimEnd() + \"\\n\" + block;\n    writeFileSync(gitignorePath, updated);\n    console.log(`[6/7] .gitignore: UPDATED`);\n    fixes++;\n  } else {\n    console.log(`[6/7] .gitignore: OK`);\n  }\n\n  // 7. .mcp.json\n  const mcpPath = join(projectRoot, \".mcp.json\");\n  let mcp: any = {};\n  if (existsSync(mcpPath)) {\n    try { mcp = JSON.parse(readFileSync(mcpPath, \"utf8\")); } catch { /* fresh */ }\n  }\n  if (!mcp.mcpServers) mcp.mcpServers = {};\n  if (!mcp.mcpServers[\"team11-memory\"]) {\n    mcp.mcpServers[\"team11-memory\"] = {\n      command: \"node\",\n      args: [\".team11/mcp-server/dist/index.js\"],\n      env: { TEAM11_MEMORY_DB: \".team11/memory.db\" }\n    };\n    writeFileSync(mcpPath, JSON.stringify(mcp, null, 2) + \"\\n\");\n    console.log(`[7/7] .mcp.json: ADDED team11-memory`);\n    fixes++;\n  } else {\n    console.log(`[7/7] .mcp.json: OK`);\n  }\n\n  console.log(`\\n${fixes === 0 ? \"Everything already set up.\" : `Fixed ${fixes} item(s).`}`);\n  console.log(`\\nNext: add \"team11-memory\" to enabledMcpjsonServers in .claude/settings.local.json, then restart Claude Code.\\n`);\n}\n\nmain();\n" });

  files.push({ path: "src/scripts/init-project.ts", content: "/**\n * init-project.ts — Initialize Team11 MCP memory in a new project.\n *\n * Usage: node dist/scripts/init-project.js [project-root]\n *\n * If project-root is omitted, uses the current working directory.\n *\n * What it does:\n *   1. Creates .team11/ directory structure\n *   2. Copies MCP server source to .team11/mcp-server/\n *   3. Runs npm install + npm run build\n *   4. Creates .team11/config.json (solo mode, no sync)\n *   5. Adds .team11/ entries to .gitignore\n *   6. Creates or updates .mcp.json with team11-memory entry\n *   7. Initializes the SQLite database (all tables)\n *   8. Prints next steps\n */\n\nimport { existsSync, mkdirSync, writeFileSync, readFileSync, copyFileSync, readdirSync, statSync } from \"node:fs\";\nimport { join, dirname, resolve, relative } from \"node:path\";\nimport { fileURLToPath } from \"node:url\";\nimport { execSync } from \"node:child_process\";\n\nconst __dirname = dirname(fileURLToPath(import.meta.url));\n\nfunction findMcpServerRoot(): string {\n  // Walk up from dist/scripts/ to find package.json\n  let dir = __dirname;\n  for (let i = 0; i < 5; i++) {\n    if (existsSync(join(dir, \"package.json\")) && existsSync(join(dir, \"src\"))) return dir;\n    dir = dirname(dir);\n  }\n  throw new Error(\"Could not find MCP server root\");\n}\n\nfunction copyDirRecursive(src: string, dest: string, exclude: string[] = []): number {\n  let count = 0;\n  mkdirSync(dest, { recursive: true });\n  for (const entry of readdirSync(src)) {\n    if (exclude.includes(entry)) continue;\n    const srcPath = join(src, entry);\n    const destPath = join(dest, entry);\n    if (statSync(srcPath).isDirectory()) {\n      count += copyDirRecursive(srcPath, destPath, exclude);\n    } else {\n      copyFileSync(srcPath, destPath);\n      count++;\n    }\n  }\n  return count;\n}\n\nconst GITIGNORE_BLOCK = `\n# Team11 state (ephemeral, gitignored)\n.team11/config.json\n.team11/memory.db\n.team11/memory.db-*\n.team11/memory.db-*\n.team11/knowledge-graph.jsonl\n.team11/logs/\n.team11/findings/\n.team11/checkpoints/\n.team11/stale/\n.team11/inboxes/\n.team11/proposals/\n.team11/hive.md\n.team11/pheromones.json\n.team11/_outbox.json\n.team11/_secretary_query.cjs\n\n# Team11 MCP server build artifacts\n.team11/mcp-server/dist/\n.team11/mcp-server/node_modules/\n\n# Allow MCP server source (safe to commit)\n!.team11/mcp-server/\n!.team11/mcp-server/src/\n!.team11/mcp-server/src/**\n!.team11/mcp-server/package.json\n!.team11/mcp-server/package-lock.json\n!.team11/mcp-server/tsconfig.json\n!.team11/mcp-server/README.md\n`;\n\nfunction main() {\n  const projectRoot = resolve(process.argv[2] || process.cwd());\n  const mcpServerSrc = findMcpServerRoot();\n  const team11Dir = join(projectRoot, \".team11\");\n  const destMcpServer = join(team11Dir, \"mcp-server\");\n\n  console.log(`\\nTeam11 Memory — Project Init`);\n  console.log(`Project root: ${projectRoot}`);\n  console.log(`Source MCP server: ${mcpServerSrc}\\n`);\n\n  // 1. Create .team11/ structure\n  const dirs = [\"logs\", \"findings\", \"checkpoints\", \"stale\", \"inboxes\", \"proposals\"];\n  for (const d of dirs) {\n    mkdirSync(join(team11Dir, d), { recursive: true });\n  }\n  console.log(`[1/7] Created .team11/ directory structure`);\n\n  // 2. Copy MCP server source (excluding dist, node_modules)\n  if (resolve(mcpServerSrc) === resolve(destMcpServer)) {\n    console.log(`[2/7] MCP server already in place (same project)`);\n  } else {\n    const copied = copyDirRecursive(mcpServerSrc, destMcpServer, [\"dist\", \"node_modules\", \".git\"]);\n    console.log(`[2/7] Copied MCP server source (${copied} files)`);\n  }\n\n  // 3. Install + build\n  console.log(`[3/7] Installing dependencies...`);\n  try {\n    execSync(\"npm install\", { cwd: destMcpServer, stdio: \"pipe\" });\n    console.log(`      npm install done`);\n    execSync(\"npm run build\", { cwd: destMcpServer, stdio: \"pipe\" });\n    console.log(`      npm run build done`);\n  } catch (err: any) {\n    console.error(`      ERROR: ${err.message}`);\n    console.error(`      Run manually: cd ${destMcpServer} && npm install && npm run build`);\n  }\n\n  // 4. Create config.json (solo, no sync)\n  const configPath = join(team11Dir, \"config.json\");\n  if (!existsSync(configPath)) {\n    writeFileSync(configPath, JSON.stringify({\n      mode: \"solo\",\n      operator: null,\n      repo: null,\n      pre_verification: {\n        enabled: false,\n        commands: []\n      }\n    }, null, 2));\n    console.log(`[4/7] Created .team11/config.json (solo mode)`);\n  } else {\n    console.log(`[4/7] .team11/config.json already exists — skipped`);\n  }\n\n  // 5. Update .gitignore\n  const gitignorePath = join(projectRoot, \".gitignore\");\n  const existing = existsSync(gitignorePath) ? readFileSync(gitignorePath, \"utf8\") : \"\";\n  if (existing.includes(\".team11/config.json\")) {\n    console.log(`[5/7] .gitignore already has Team11 entries — skipped`);\n  } else {\n    // Remove any blanket .team11/ ignore\n    let updated = existing.replace(/^\\.team11\\/\\s*$/m, \"\");\n    updated = updated.trimEnd() + \"\\n\" + GITIGNORE_BLOCK;\n    writeFileSync(gitignorePath, updated);\n    console.log(`[5/7] Updated .gitignore with Team11 entries`);\n  }\n\n  // 6. Create/update .mcp.json\n  const mcpJsonPath = join(projectRoot, \".mcp.json\");\n  let mcpConfig: any = {};\n  if (existsSync(mcpJsonPath)) {\n    try { mcpConfig = JSON.parse(readFileSync(mcpJsonPath, \"utf8\")); } catch { /* fresh */ }\n  }\n  if (!mcpConfig.mcpServers) mcpConfig.mcpServers = {};\n  if (!mcpConfig.mcpServers[\"team11-memory\"]) {\n    mcpConfig.mcpServers[\"team11-memory\"] = {\n      command: \"node\",\n      args: [\".team11/mcp-server/dist/index.js\"],\n      env: {\n        TEAM11_MEMORY_DB: \".team11/memory.db\"\n      }\n    };\n    writeFileSync(mcpJsonPath, JSON.stringify(mcpConfig, null, 2) + \"\\n\");\n    console.log(`[6/7] Added team11-memory to .mcp.json`);\n  } else {\n    console.log(`[6/7] team11-memory already in .mcp.json — skipped`);\n  }\n\n  // 7. Initialize the database\n  try {\n    const dbPath = join(team11Dir, \"memory.db\");\n    // Dynamic import of the built db module\n    const initScript = `\n      import { initDb } from './dist/db.js';\n      const db = initDb('${dbPath.replace(/\\\\/g, \"/\")}');\n      const tables = db.prepare(\"SELECT COUNT(*) as c FROM sqlite_master WHERE type='table'\").get();\n      console.log(JSON.stringify(tables));\n      db.close();\n    `;\n    const result = execSync(`node --input-type=module -e \"${initScript.replace(/\"/g, '\\\\\"').replace(/\\n/g, \" \")}\"`, {\n      cwd: destMcpServer,\n      encoding: \"utf8\",\n      stdio: [\"pipe\", \"pipe\", \"pipe\"],\n    });\n    const parsed = JSON.parse(result.trim());\n    console.log(`[7/7] Database initialized (${parsed.c} tables)`);\n  } catch (err: any) {\n    console.log(`[7/7] Database will be initialized on first MCP server start`);\n  }\n\n  // 8. Create empty pheromones.json\n  const pheromonePath = join(team11Dir, \"pheromones.json\");\n  if (!existsSync(pheromonePath)) {\n    writeFileSync(pheromonePath, JSON.stringify({ trails: [] }, null, 2));\n  }\n\n  // 9. Create empty hive.md\n  const hivePath = join(team11Dir, \"hive.md\");\n  if (!existsSync(hivePath)) {\n    const projectName = projectRoot.split(/[\\\\/]/).pop() || \"project\";\n    writeFileSync(hivePath, `# Hive Mind\n**Project:** ${projectName}\n**Date:** ${new Date().toISOString().split(\"T\")[0]}\n**Type:** hive-mind\n**Version:** 1\n\n## Active Edits\n| Pair | Agent | File | Action | Status | Timestamp |\n|------|-------|------|--------|--------|-----------|\n\n## Discovered Facts\n| ID | Fact | Source | Confidence | Last Reinforced | Timestamp |\n|----|------|--------|------------|-----------------|-----------|\n\n## Decisions\n| ID | Decision | Rationale | Decided By | Timestamp |\n|----|----------|-----------|------------|-----------|\n\n## Contradictions\n| ID | Claim A | Source A | Claim B | Source B | Resolution | Status |\n|----|---------|----------|---------|----------|------------|--------|\n\n## Pheromone Trails\n| Date | Pair | Task | Difficulty | Files Touched | Gotchas | Duration |\n|------|------|------|------------|---------------|---------|----------|\n`);\n  }\n\n  console.log(`\nTEAM11 MEMORY INITIALIZED\n  Project: ${projectRoot}\n  DB: .team11/memory.db\n  MCP: .team11/mcp-server/ (${existsSync(join(destMcpServer, \"dist\", \"index.js\")) ? \"built\" : \"needs build\"})\n  Mode: solo (no sync)\n\nNext steps:\n  1. Add \"team11-memory\" to enabledMcpjsonServers in .claude/settings.local.json\n  2. Restart Claude Code\n  3. Run /team11 setup to create worktrees\n  4. (Optional) Add Turso sync: edit .team11/config.json with sync block\n`);\n}\n\nmain();\n" });

  files.push({ path: "src/scripts/process-pair-log.ts", content: "/**\n * process-pair-log.ts — The Secretary carrier (Team11 defect D4, Mode A).\n *\n * Reads Team11 pair logs, extracts NEW `[OUTBOX:*]` markers (plus the\n * `[FACT]` / `[GOTCHA]` / `[REINFORCED]` / `[CONTRADICTION]` line prefixes and\n * `QUESTION FOR HUMAN`), and writes them into the memory DB — reusing the\n * existing write primitives (`initDb`, `storeEmbedding`) and Turso sync. It is\n * a ONE-SHOT, idempotent processor: it is NOT a poll/sleep loop.\n *\n * Trigger models (it is correct under BOTH):\n *   1. Event-driven SubagentStop hook (WIRED + VERIFIED 2026-05-29): a\n *      `.claude/settings.local.json` hook on matcher \"team11-coder-auditor\" runs\n *      this on every pair completion. The hook passes only the project root on\n *      stdin (no pair identity), so the default \"scan all logs\" behaviour is what\n *      it needs. It NO LONGER needs `--all-history`: a freshly-created (live) pair\n *      log is now recognised by its filesystem mtime (within\n *      BACKLOG_MTIME_WINDOW_MS, default 48h) and processed in full, while an old\n *      historical log is still baseline-skipped (see the backlog guard + the\n *      `--all-history` flag below). The single-flight lock makes concurrent\n *      firings (multiple pairs finishing at once) safe.\n *   2. CEO-driven (fallback / manual): the CEO runs this between dispatches.\n *\n *   HARNESS NOTE — VERIFIED 2026-05-29 (CC 2.1.156, live SubagentStop probe +\n *   end-to-end test): Stop/SubagentStop DO fire for subagents spawned with\n *   run_in_background=true. The older issue #25147 (\"background agents bypass\n *   Stop hooks\", CLOSED not-planned) was superseded by #33049 + #58637 (both\n *   COMPLETED). The payload carries agent_id/agent_type/background_tasks/\n *   stop_hook_active but NO pair-log path — hence scan-all + mtime-based\n *   live-log detection (no `--all-history` needed). High-concurrency foot-gun:\n *   see #58637; the single-flight lock + scan-all idempotency cover it.\n *\n * Idempotency: a per-log high-water mark (line count) is persisted in\n * `.team11/_secretary_state.json`. Re-running only processes lines added since\n * the last successful run, so double-writes do not happen. A\n * `[SECRETARY:PROCESSED ...]` marker is also appended to each log it advances.\n *\n * Usage:\n *   node dist/scripts/process-pair-log.js [projectRoot] [options]\n *   node dist/scripts/process-pair-log.js [path/to/.team11/logs/pair-N.md] [options]\n *\n * Options:\n *   --pair <id>        Process only logs/pair-<id>.md (e.g. --pair 3).\n *   --log <path>       Process exactly this log file (must live under .team11/logs/).\n *   --project <path>   Project root (default: PROJECT_ROOT env, then walk up from script).\n *   --all-history      Explicit override: process the ENTIRE log even with no prior\n *                      high-water mark, REGARDLESS of the log's mtime. Rarely needed\n *                      now — a never-processed log is auto-classified by its file\n *                      mtime: if it was modified within BACKLOG_MTIME_WINDOW_MS\n *                      (default 48h, overridable via TEAM11_BACKLOG_WINDOW_HOURS) it\n *                      is a LIVE pair log and is ingested from line 0 automatically;\n *                      only an OLDER, never-processed log with no [SECRETARY:PROCESSED]\n *                      marker is treated as historical backlog and SKIPPED (a marker\n *                      is written at the current end so future entries are picked up).\n *                      Use this flag to force-ingest a stale/historical log on demand.\n *   --dry-run          Parse + report, but do not write to the DB, advance the\n *                      high-water mark, or append markers.\n *\n * Exit code 0 on success (even with per-entry parse errors, which are reported).\n * Non-zero only on fatal setup errors (bad path, DB init failure).\n */\n\nimport {\n  readFileSync,\n  writeFileSync,\n  existsSync,\n  appendFileSync,\n  readdirSync,\n  mkdirSync,\n  rmSync,\n  renameSync,\n  statSync,\n} from \"node:fs\";\nimport { join, dirname, resolve, relative, isAbsolute } from \"node:path\";\nimport { fileURLToPath } from \"node:url\";\nimport { initDb } from \"../db.js\";\nimport { storeEmbedding } from \"../tools/store.js\";\nimport { initEmbeddings } from \"../embeddings.js\";\nimport { loadSyncConfig, initSync, forceSync, shutdownSync } from \"../sync.js\";\n\nconst __dirname = dirname(fileURLToPath(import.meta.url));\n\n// --- backlog recency window ----------------------------------------------\n//\n// A pair log that has never been processed (no high-water mark) AND has no\n// [SECRETARY:PROCESSED] marker is ambiguous: it could be a freshly-created LIVE\n// pair log (its first markers waiting to be ingested) or an OLD historical log\n// from a past session (mass-ingest hazard). We disambiguate by the file's\n// MODIFICATION TIME (fs.statSync().mtimeMs):\n//   - mtime within the window  => LIVE  => process from line 0 (like --all-history)\n//   - mtime older than window  => stale => baseline-skip (just set the mark)\n// This removes the carrier's one fragile dependency: the SubagentStop hook no\n// longer needs --all-history, and deleting _secretary_state.json no longer\n// re-ingests every old log — only logs touched within the window come back.\n//\n// Default 48h. Tunable at runtime via TEAM11_BACKLOG_WINDOW_HOURS (a positive\n// finite number of hours); anything missing/invalid falls back to the default.\nconst DEFAULT_BACKLOG_WINDOW_HOURS = 48;\n\nfunction resolveBacklogWindowMs(): number {\n  const raw = process.env.TEAM11_BACKLOG_WINDOW_HOURS;\n  if (raw !== undefined && raw.trim() !== \"\") {\n    const hours = Number(raw);\n    if (Number.isFinite(hours) && hours > 0) return hours * 60 * 60 * 1000;\n    console.error(\n      `[process-pair-log] WARNING: ignoring invalid TEAM11_BACKLOG_WINDOW_HOURS=${raw} (want a positive number); using default ${DEFAULT_BACKLOG_WINDOW_HOURS}h`,\n    );\n  }\n  return DEFAULT_BACKLOG_WINDOW_HOURS * 60 * 60 * 1000;\n}\n\nconst BACKLOG_MTIME_WINDOW_MS = resolveBacklogWindowMs();\n\n// --- types ---------------------------------------------------------------\n\ninterface OutboxEntry {\n  type: string;\n  [key: string]: unknown;\n}\n\ninterface WriteResults {\n  facts: number;\n  pheromones: number;\n  gotchas: number;\n  contradictions: number;\n  reinforced: number;\n  released: number;\n  questions: number;\n  skipped: number;\n  errors: number;\n}\n\ninterface LogResult {\n  log: string;\n  linesScanned: number;\n  fromLine: number;\n  processed: boolean;\n  reason?: string;\n  results: WriteResults;\n}\n\n// Per-log high-water mark state. Keyed by log path RELATIVE to project root\n// (posix-normalised) so the state file is portable across machines/operators.\ntype SecretaryState = Record<string, { lines: number; updated_at: string }>;\n\nfunction emptyResults(): WriteResults {\n  return {\n    facts: 0,\n    pheromones: 0,\n    gotchas: 0,\n    contradictions: 0,\n    reinforced: 0,\n    released: 0,\n    questions: 0,\n    skipped: 0,\n    errors: 0,\n  };\n}\n\n// --- project root / paths ------------------------------------------------\n\nfunction findProjectRoot(explicit?: string): string {\n  if (explicit) return resolve(explicit);\n  if (process.env.PROJECT_ROOT) return resolve(process.env.PROJECT_ROOT);\n  let dir = __dirname;\n  for (let i = 0; i < 10; i++) {\n    if (existsSync(join(dir, \".team11\"))) return dir;\n    const parent = dirname(dir);\n    if (parent === dir) break;\n    dir = parent;\n  }\n  throw new Error(\"Could not find project root (no .team11/ directory found)\");\n}\n\n/** Posix-normalised path relative to project root (state-file key + marker text). */\nfunction relKey(projectRoot: string, absPath: string): string {\n  return relative(projectRoot, absPath).split(\"\\\\\").join(\"/\");\n}\n\n/**\n * Resolve and validate a log path. SECURITY: the resolved path MUST live inside\n * `<projectRoot>/.team11/logs/`. Anything else (path traversal, absolute escape)\n * is rejected. No shell interpolation anywhere — paths are used only with fs.\n */\nfunction resolveLogPathSafe(projectRoot: string, candidate: string): string {\n  const logsDir = resolve(join(projectRoot, \".team11\", \"logs\"));\n  const abs = isAbsolute(candidate)\n    ? resolve(candidate)\n    : resolve(join(projectRoot, candidate));\n  const rel = relative(logsDir, abs);\n  if (rel.startsWith(\"..\") || isAbsolute(rel)) {\n    throw new Error(\n      `Refusing to process log outside .team11/logs/: ${candidate} (resolved ${abs})`,\n    );\n  }\n  return abs;\n}\n\nfunction discoverPairLogs(projectRoot: string): string[] {\n  const logsDir = join(projectRoot, \".team11\", \"logs\");\n  if (!existsSync(logsDir)) return [];\n  return readdirSync(logsDir)\n    .filter((f) => f.startsWith(\"pair-\") && f.endsWith(\".md\"))\n    .sort()\n    .map((f) => join(logsDir, f));\n}\n\n// --- state ---------------------------------------------------------------\n\nfunction statePath(projectRoot: string): string {\n  return join(projectRoot, \".team11\", \"_secretary_state.json\");\n}\n\nfunction loadState(projectRoot: string): SecretaryState {\n  const p = statePath(projectRoot);\n  if (!existsSync(p)) return {};\n  try {\n    const parsed = JSON.parse(readFileSync(p, \"utf8\"));\n    return parsed && typeof parsed === \"object\" ? (parsed as SecretaryState) : {};\n  } catch (err) {\n    console.error(`[process-pair-log] WARNING: could not parse ${p}, treating as empty:`, err);\n    return {};\n  }\n}\n\nfunction saveState(projectRoot: string, state: SecretaryState): void {\n  writeFileSync(statePath(projectRoot), JSON.stringify(state, null, 2) + \"\\n\");\n}\n\n// --- single-flight lock --------------------------------------------------\n//\n// This carrier is about to be wired to a SubagentStop hook that fires once per\n// pair completion. If 2+ pairs finish at the same instant, multiple copies run\n// at once and would race on the shared SQLite DB (better-sqlite3), the pair\n// logs, and the per-log high-water-mark state file. We serialise the WRITE path\n// with a single-flight lock so only one copy mutates state at a time.\n//\n// Atomicity: the lock is a DIRECTORY created with mkdirSync. mkdir is atomic at\n// the syscall level — it either creates the dir (we win) or throws EEXIST (held\n// by someone else). There is NO check-then-act window (we never existsSync then\n// mkdir), so there is no TOCTOU race between two racing processes.\n//\n// Because the holder scans ALL pair logs (default behaviour), a copy that fails\n// to acquire loses NO work by bailing: the holder will pick up every marker the\n// bailing copy would have. So lock-held is a clean exit-0, not an error.\n\nconst LOCK_DIR_NAME = \"_secretary.lock\";\nconst LOCK_META_NAME = \"owner.json\";\nconst STALE_LOCK_MS = 120_000; // 120s: holder presumably crashed past this.\n\nfunction lockDirPath(projectRoot: string): string {\n  return join(projectRoot, \".team11\", LOCK_DIR_NAME);\n}\n\ninterface LockMeta {\n  pid: number;\n  acquired_at: string; // ISO-8601\n}\n\n/**\n * Read the lock owner metadata. Best-effort: a partially-written, missing, or\n * malformed meta file returns null (caller treats null as \"unknown age\").\n */\nfunction readLockMeta(dir: string): LockMeta | null {\n  try {\n    const raw = readFileSync(join(dir, LOCK_META_NAME), \"utf8\");\n    const parsed = JSON.parse(raw);\n    if (parsed && typeof parsed === \"object\" && typeof parsed.acquired_at === \"string\") {\n      return parsed as LockMeta;\n    }\n    return null;\n  } catch {\n    return null;\n  }\n}\n\n/**\n * Try to atomically create the lock dir and stamp owner metadata into it.\n * Returns true on success. Throws only on EEXIST (already held) — every other\n * fs error propagates (a real failure we must not mask).\n */\nfunction tryCreateLock(dir: string): boolean {\n  try {\n    mkdirSync(dir); // atomic; NO { recursive: true } — recursive makes EEXIST silent.\n  } catch (err) {\n    if ((err as NodeJS.ErrnoException)?.code === \"EEXIST\") return false;\n    throw err;\n  }\n  // We own the dir. Stamp ownership. If this write fails the dir still exists,\n  // so the finally-release path (rmSync recursive) still cleans it up.\n  const meta: LockMeta = { pid: process.pid, acquired_at: new Date().toISOString() };\n  writeFileSync(join(dir, LOCK_META_NAME), JSON.stringify(meta) + \"\\n\");\n  return true;\n}\n\n/**\n * Acquire the single-flight lock.\n *\n * Returns true if we now hold it, false if another live copy holds it (caller\n * should exit 0 cleanly).\n *\n * Stale-lock recovery uses a COMPARE-AND-SWAP via atomic rename, NOT a naive\n * \"rmSync(dir) then mkdir(dir)\". The naive form has a corrupting race: two\n * stealers, or a stealer + a just-arrived fresh holder, can interleave such that\n * one stealer rmSync's a lock another process just freshly created, leaving TWO\n * processes both believing they own the lock. We avoid that:\n *\n *   1. Atomically rename the stale dir aside to a unique victim path. renameSync\n *      is atomic, so at most ONE stealer can move a given dir; a racing stealer\n *      gets ENOENT and falls through to a plain create (where mkdir arbitrates).\n *   2. After winning the rename, re-read the meta we physically moved. If its\n *      acquired_at no longer matches what we observed as stale, a fresh holder\n *      had re-created the dir and we renamed a LIVE lock by mistake — so we\n *      restore it (rename back) and bail. This is the CAS check: we only proceed\n *      if the thing we stole is the exact stale instance we decided to steal.\n *   3. Only then drop the old dir and re-create. mkdir remains the sole owner-\n *      ship arbiter, so a third racer that created dir in the meantime makes our\n *      mkdir EEXIST and we bail cleanly.\n *\n * Net: mkdir(dir) success is the ONE-AND-ONLY ownership signal, and no process\n * ever removes a `dir` it did not first atomically rename-away, so double-\n * acquire is impossible.\n */\nfunction acquireLock(projectRoot: string): boolean {\n  const dir = lockDirPath(projectRoot);\n\n  if (tryCreateLock(dir)) return true;\n\n  // Held by someone. Decide if it's stale. A missing/malformed meta (null) is\n  // treated as stale ENOUGH to attempt a steal — the CAS below still protects a\n  // live holder that simply hasn't finished stamping its meta yet.\n  const meta = readLockMeta(dir);\n  const ageMs = meta ? Date.now() - Date.parse(meta.acquired_at) : Infinity;\n  const isStale = !meta || !Number.isFinite(ageMs) || ageMs > STALE_LOCK_MS;\n  if (!isStale) return false; // fresh lock, real holder — bail cleanly.\n\n  console.error(\n    `[process-pair-log] Attempting steal of stale lock (age ${Number.isFinite(ageMs) ? Math.round(ageMs / 1000) + \"s\" : \"unknown\"}, pid ${meta?.pid ?? \"?\"})`,\n  );\n\n  const victim = `${dir}.stale-${process.pid}-${Date.now()}`;\n  try {\n    renameSync(dir, victim); // atomic; only one stealer can win this move.\n  } catch (err) {\n    // ENOENT => another stealer already moved/removed it, or the holder released\n    // it. Either way the dir slot may now be free or freshly taken; let mkdir\n    // arbitrate. Any non-ENOENT error also falls through to the safe create.\n    if ((err as NodeJS.ErrnoException)?.code !== \"ENOENT\") {\n      console.error(\"[process-pair-log] Stale-lock rename failed (falling back to create):\", err);\n    }\n    return tryCreateLock(dir);\n  }\n\n  // CAS check: confirm what we moved is the SAME stale instance we observed. If\n  // a fresh holder re-created `dir` between our staleness read and our rename, we\n  // just moved their LIVE lock — restore it and bail rather than corrupt.\n  const moved = readLockMeta(victim);\n  const stillSameStale =\n    // both null-meta: nothing changed underneath us (still the meta-less lock).\n    (!meta && !moved) ||\n    // both present and acquired_at identical: same instance we decided to steal.\n    (!!meta && !!moved && moved.acquired_at === meta.acquired_at);\n  if (!stillSameStale) {\n    console.error(\"[process-pair-log] Lock changed under steal — restoring and bailing.\");\n    try {\n      renameSync(victim, dir); // put it back for the rightful (fresh) holder.\n    } catch {\n      // Couldn't restore (a third party already re-created dir). Drop our copy.\n      try {\n        rmSync(victim, { recursive: true, force: true });\n      } catch {\n        /* best-effort */\n      }\n    }\n    return false;\n  }\n\n  // Confirmed stale. Discard the dead dir and re-create. mkdir is still the sole\n  // arbiter: if a racer created `dir` after our rename, we EEXIST and bail.\n  try {\n    rmSync(victim, { recursive: true, force: true });\n  } catch (err) {\n    console.error(\"[process-pair-log] Could not delete stolen stale lock (continuing):\", err);\n  }\n  return tryCreateLock(dir);\n}\n\n/** Release the lock we hold. Best-effort + idempotent — never throws. */\nfunction releaseLock(projectRoot: string): void {\n  try {\n    rmSync(lockDirPath(projectRoot), { recursive: true, force: true });\n  } catch (err) {\n    console.error(\"[process-pair-log] WARNING: could not release lock (stale-steal will recover):\", err);\n  }\n}\n\n// --- parsing -------------------------------------------------------------\n\nconst OUTBOX_TYPE_BY_TAG: Record<string, string> = {\n  FACT: \"fact\",\n  PHEROMONE: \"pheromone\",\n  GOTCHA: \"gotcha\",\n  CONTRADICTION: \"contradiction\",\n  RELEASE_FILES: \"release_files\",\n  REINFORCED: \"reinforced\",\n};\n\n// `[OUTBOX:FACT] { ...json... }` — tag, then a JSON object on the same line.\nconst OUTBOX_RE = /\\[OUTBOX:([A-Z_]+)\\]\\s*(\\{.*\\})\\s*$/;\n// Plain prose prefixes (per coder-auditor.md \"Communication Rules\"). These are\n// best-effort: free text, not JSON. We map them to findings/contradictions.\nconst FACT_PREFIX_RE = /\\[FACT\\]\\s*(.+)$/;\nconst GOTCHA_PREFIX_RE = /\\[GOTCHA\\]\\s*(.+)$/;\nconst REINFORCED_PREFIX_RE = /\\[REINFORCED\\]\\s*(.+)$/;\nconst CONTRADICTION_PREFIX_RE = /\\[CONTRADICTION\\]\\s*(.+)$/;\nconst QUESTION_RE = /QUESTION FOR HUMAN:?\\s*(.*)$/;\nconst PROCESSED_MARKER = \"[SECRETARY:PROCESSED\";\n\n/** A parsed entry, tagged with its source log (source_file provenance + dedupe). */\ninterface ParsedLine {\n  entry: OutboxEntry;\n}\n\n/**\n * Extract structured entries from a slice of log lines.\n * `sourceRel` is the relative log path, stamped as source_file so the\n * findings UNIQUE(title, source_file) constraint dedupes across re-runs.\n */\nfunction parseLines(lines: string[], sourceRel: string): {\n  parsed: ParsedLine[];\n  parseErrors: number;\n} {\n  const parsed: ParsedLine[] = [];\n  let parseErrors = 0;\n\n  for (const line of lines) {\n    const trimmed = line.trim();\n    if (!trimmed) continue;\n\n    // 1. Structured [OUTBOX:*] {json}\n    const ob = OUTBOX_RE.exec(trimmed);\n    if (ob) {\n      const tag = ob[1];\n      const type = OUTBOX_TYPE_BY_TAG[tag];\n      if (!type) {\n        console.error(`[process-pair-log] Unknown OUTBOX tag: ${tag} — skipping`);\n        parseErrors++;\n        continue;\n      }\n      try {\n        const obj = JSON.parse(ob[2]) as Record<string, unknown>;\n        parsed.push({ entry: { type, source_file: sourceRel, ...obj } });\n      } catch (err) {\n        console.error(`[process-pair-log] Malformed OUTBOX JSON, skipping: ${trimmed.slice(0, 120)}`, err);\n        parseErrors++;\n      }\n      continue;\n    }\n\n    // 2. Prose [FACT]/[GOTCHA]/[REINFORCED]/[CONTRADICTION]/QUESTION prefixes.\n    //    These do NOT duplicate an [OUTBOX:*] line (an OUTBOX line is matched\n    //    above and `continue`d), so the same fact written both ways on the same\n    //    line is impossible. Different lines for the same fact dedupe via the\n    //    UNIQUE(title, source_file) constraint at insert time.\n    const reinforced = REINFORCED_PREFIX_RE.exec(trimmed);\n    if (reinforced) {\n      // Prose reinforce has no finding_id — record as a low-importance note so\n      // the signal isn't lost, but it cannot UPDATE a row (needs an id).\n      parsed.push({\n        entry: {\n          type: \"reinforced_note\",\n          source_file: sourceRel,\n          content: reinforced[1].trim(),\n        },\n      });\n      continue;\n    }\n    const contradiction = CONTRADICTION_PREFIX_RE.exec(trimmed);\n    if (contradiction) {\n      parsed.push({\n        entry: {\n          type: \"contradiction_note\",\n          source_file: sourceRel,\n          content: contradiction[1].trim(),\n        },\n      });\n      continue;\n    }\n    const fact = FACT_PREFIX_RE.exec(trimmed);\n    if (fact) {\n      parsed.push({\n        entry: {\n          type: \"fact\",\n          source_file: sourceRel,\n          title: deriveTitle(fact[1]),\n          content: fact[1].trim(),\n          confidence: \"medium\",\n        },\n      });\n      continue;\n    }\n    const gotcha = GOTCHA_PREFIX_RE.exec(trimmed);\n    if (gotcha) {\n      parsed.push({\n        entry: {\n          type: \"gotcha\",\n          source_file: sourceRel,\n          title: deriveTitle(gotcha[1]),\n          content: gotcha[1].trim(),\n        },\n      });\n      continue;\n    }\n    const question = QUESTION_RE.exec(trimmed);\n    if (question) {\n      parsed.push({\n        entry: { type: \"question\", source_file: sourceRel, content: trimmed },\n      });\n      continue;\n    }\n  }\n\n  return { parsed, parseErrors };\n}\n\n/** Short title from a free-text prose line (first sentence/clause, capped). */\nfunction deriveTitle(text: string): string {\n  const cleaned = text.trim().replace(/\\s+/g, \" \");\n  const cut = cleaned.split(/[.:—–-]/)[0].trim() || cleaned;\n  return cut.length > 80 ? cut.slice(0, 77) + \"...\" : cut;\n}\n\n// --- DB writes (reusing initDb + storeEmbedding) -------------------------\n\ninterface DbHandle {\n  // Minimal structural shape of the better-sqlite3 Database we rely on.\n  prepare(sql: string): {\n    run(...params: unknown[]): { lastInsertRowid: number | bigint };\n  };\n  close(): void;\n}\n\n/**\n * Write one parsed entry. Mirrors the table contracts in write-and-sync.ts /\n * store.ts, and — unlike write-and-sync.ts — calls storeEmbedding() after each\n * finding/gotcha insert so semantic (vector) search stays consistent. Surfacing\n * (questions, prose-only contradictions/reinforces) is logged for the CEO, not\n * silently dropped. Returns the type key incremented (or \"errors\"/\"skipped\").\n */\nasync function writeEntry(\n  db: DbHandle,\n  entry: OutboxEntry,\n  surfaced: string[],\n): Promise<keyof WriteResults> {\n  switch (entry.type) {\n    case \"fact\": {\n      const res = db\n        .prepare(\n          `INSERT INTO findings (title, content, type, confidence, importance, source_pair, source_file, tags)\n           VALUES (?, ?, 'fact', ?, 0.6, ?, ?, ?)`,\n        )\n        .run(\n          entry.title as string,\n          entry.content as string,\n          (entry.confidence as string) ?? \"high\",\n          (entry.pair as string) ?? null,\n          (entry.source_file as string) ?? null,\n          entry.tags ? JSON.stringify(entry.tags) : null,\n        );\n      await storeEmbedding(db as never, res.lastInsertRowid, `${entry.title} ${entry.content}`);\n      return \"facts\";\n    }\n\n    case \"pheromone\": {\n      db.prepare(\n        `INSERT INTO pheromones (task, pair, difficulty, files_touched, gotchas, duration_minutes, estimated_duration_minutes, rounds, findings_count, verdict_breakdown)\n         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,\n      ).run(\n        entry.task as string,\n        (entry.pair as string) ?? null,\n        (entry.difficulty as string) ?? \"MEDIUM\",\n        JSON.stringify((entry.files_touched as string[]) ?? []),\n        JSON.stringify((entry.gotchas as string[]) ?? []),\n        (entry.actual_duration_min as number) ?? null,\n        (entry.estimated_duration_min as number) ?? null,\n        (entry.rounds as number) ?? null,\n        (entry.findings_count as number) ?? null,\n        entry.verdict_breakdown ? JSON.stringify(entry.verdict_breakdown) : null,\n      );\n      return \"pheromones\";\n    }\n\n    case \"gotcha\": {\n      const content = entry.evidence\n        ? `${entry.content}\\n\\nEvidence: ${entry.evidence}`\n        : (entry.content as string);\n      const res = db\n        .prepare(\n          `INSERT INTO findings (title, content, type, confidence, importance, source_pair, source_file, tags)\n           VALUES (?, ?, 'gotcha', 'high', 0.7, ?, ?, ?)`,\n        )\n        .run(\n          entry.title as string,\n          content,\n          (entry.pair as string) ?? null,\n          (entry.source_file as string) ?? null,\n          entry.tags ? JSON.stringify(entry.tags) : null,\n        );\n      await storeEmbedding(db as never, res.lastInsertRowid, `${entry.title} ${content}`);\n      return \"gotchas\";\n    }\n\n    case \"contradiction\": {\n      db.prepare(\n        `INSERT INTO contradictions (claim_a, source_a, claim_b, source_b, status)\n         VALUES (?, ?, ?, ?, 'OPEN')`,\n      ).run(\n        entry.claim_a as string,\n        entry.source_a as string,\n        entry.claim_b as string,\n        entry.source_b as string,\n      );\n      return \"contradictions\";\n    }\n\n    case \"reinforced\": {\n      // Structured reinforce carries an explicit finding id (fact_id|finding_id).\n      const id = (entry.finding_id as number) ?? (entry.fact_id as number);\n      if (id == null) {\n        surfaced.push(`reinforced (no id): ${JSON.stringify(entry).slice(0, 120)}`);\n        return \"skipped\";\n      }\n      db.prepare(\n        `UPDATE findings SET confidence_score = MIN(1.0, COALESCE(confidence_score,1.0) + 0.2),\n           last_reinforced = datetime('now'), updated_at = datetime('now') WHERE id = ?`,\n      ).run(id);\n      return \"reinforced\";\n    }\n\n    case \"release_files\": {\n      db.prepare(\n        `UPDATE active_edits SET released_at = datetime('now'), status = 'merged'\n         WHERE pair_id = ? AND released_at IS NULL`,\n      ).run(entry.pair_id as string);\n      return \"released\";\n    }\n\n    // Prose-only signals — surfaced to the CEO, never silently dropped, but not\n    // structurally written (they lack the fields the structured forms require).\n    case \"reinforced_note\":\n    case \"contradiction_note\":\n    case \"question\": {\n      surfaced.push(`${entry.type}: ${String(entry.content).slice(0, 160)}`);\n      return entry.type === \"question\" ? \"questions\" : \"skipped\";\n    }\n\n    default:\n      console.error(`[process-pair-log] Unknown entry type: ${entry.type}`);\n      return \"errors\";\n  }\n}\n\n// --- per-log processing --------------------------------------------------\n\nasync function processLog(\n  db: DbHandle,\n  projectRoot: string,\n  logPath: string,\n  state: SecretaryState,\n  opts: { allHistory: boolean; dryRun: boolean },\n  surfaced: string[],\n): Promise<LogResult> {\n  const rel = relKey(projectRoot, logPath);\n  const results = emptyResults();\n\n  if (!existsSync(logPath)) {\n    return { log: rel, linesScanned: 0, fromLine: 0, processed: false, reason: \"missing\", results };\n  }\n\n  const allLines = readFileSync(logPath, \"utf8\").split(/\\r?\\n/);\n  const total = allLines.length;\n  const prior = state[rel]?.lines ?? 0;\n\n  // First-run backlog guard: a log we've never processed AND that has no\n  // PROCESSED marker is AMBIGUOUS — it is either a freshly-created LIVE pair log\n  // (whose first markers we DO want) or an OLD historical log (mass-ingest\n  // hazard). We disambiguate by the file's mtime instead of forcing the caller\n  // to pass --all-history:\n  //   - mtime within BACKLOG_MTIME_WINDOW_MS  => LIVE  => fall through, ingest\n  //     from line 0 (prior === 0), exactly as --all-history would for this log.\n  //   - mtime older than the window           => stale => baseline-skip (set the\n  //     mark at the current end so future entries are picked up).\n  // --all-history remains an explicit override that forces full ingest here\n  // regardless of mtime (it short-circuits this whole guard via the condition).\n  const hasMarker = allLines.some((l) => l.includes(PROCESSED_MARKER));\n  if (prior === 0 && !hasMarker && !opts.allHistory) {\n    // mtimeMs via statSync. A stat failure (e.g. the file was deleted in the\n    // race between existsSync above and here) is treated as \"not recent\" — the\n    // conservative choice: never mass-ingest on an unreadable mtime. ageMs is\n    // clamped at >= 0 so a clock-skewed future mtime still counts as recent.\n    let ageMs = Infinity;\n    try {\n      ageMs = Math.max(0, Date.now() - statSync(logPath).mtimeMs);\n    } catch (err) {\n      console.error(`[process-pair-log] WARNING: statSync failed for ${rel}, treating as backlog:`, err);\n    }\n    // Boundary is inclusive (ageMs === window => LIVE) so \"exactly at the\n    // window\" is deterministic: a log right on the edge is still processed.\n    const isRecent = ageMs <= BACKLOG_MTIME_WINDOW_MS;\n    if (!isRecent) {\n      if (!opts.dryRun) {\n        state[rel] = { lines: total, updated_at: new Date().toISOString() };\n      }\n      return {\n        log: rel,\n        linesScanned: 0,\n        fromLine: 0,\n        processed: false,\n        reason: `backlog-skipped (no prior mark, no marker, mtime age ${Math.round(ageMs / 3600000)}h > window ${Math.round(BACKLOG_MTIME_WINDOW_MS / 3600000)}h; pass --all-history to force-ingest)`,\n        results,\n      };\n    }\n    // Recent => LIVE pair log: fall through and ingest from line 0.\n  }\n\n  const fromLine = prior;\n  const slice = allLines.slice(fromLine);\n  if (slice.length === 0) {\n    return { log: rel, linesScanned: 0, fromLine, processed: true, reason: \"up-to-date\", results };\n  }\n\n  const { parsed, parseErrors } = parseLines(slice, rel);\n  results.errors += parseErrors;\n\n  if (opts.dryRun) {\n    for (const p of parsed) tallyDry(p.entry, results, surfaced);\n    return { log: rel, linesScanned: slice.length, fromLine, processed: false, reason: \"dry-run\", results };\n  }\n\n  for (const p of parsed) {\n    try {\n      const key = await writeEntry(db, p.entry, surfaced);\n      results[key]++;\n    } catch (err) {\n      // UNIQUE(title, source_file) collisions (idempotent re-writes of the same\n      // fact/gotcha) land here and are counted as skipped, not errors.\n      const msg = String((err as Error)?.message ?? err);\n      if (/UNIQUE constraint failed/i.test(msg)) {\n        results.skipped++;\n      } else {\n        console.error(`[process-pair-log] Error writing ${p.entry.type} from ${rel}:`, err);\n        results.errors++;\n      }\n    }\n  }\n\n  // Always advance the high-water mark past the lines we scanned, so the same\n  // lines are never re-processed. Only APPEND a PROCESSED marker when there was\n  // something to process — a no-op scan (e.g. lines added by a previous marker,\n  // or non-OUTBOX prose) must not litter the log with \"0 entries\" markers or\n  // make the mark oscillate. When we do append, the marker adds 2 lines\n  // (leading \"\\n\" + the marker line); account for them so the next run starts\n  // clean past the marker. (append-only; never mutate existing log content.)\n  if (parsed.length > 0) {\n    const counted =\n      results.facts + results.pheromones + results.gotchas + results.contradictions + results.reinforced + results.released;\n    appendFileSync(\n      logPath,\n      `\\n[SECRETARY:PROCESSED] ${counted} entries (lines ${fromLine + 1}-${total}) at ${new Date().toISOString()}\\n`,\n    );\n    // total lines after append: original `total` + the \"\\n\" split boundary +\n    // marker line. readFileSync(...).split adds one element per newline; the\n    // appended \"\\n...marker...\\n\" contributes 2 new array elements.\n    state[rel] = { lines: total + 2, updated_at: new Date().toISOString() };\n  } else {\n    state[rel] = { lines: total, updated_at: new Date().toISOString() };\n  }\n\n  return { log: rel, linesScanned: slice.length, fromLine, processed: true, results };\n}\n\nfunction tallyDry(entry: OutboxEntry, results: WriteResults, surfaced: string[]): void {\n  switch (entry.type) {\n    case \"fact\": results.facts++; break;\n    case \"pheromone\": results.pheromones++; break;\n    case \"gotcha\": results.gotchas++; break;\n    case \"contradiction\": results.contradictions++; break;\n    case \"reinforced\":\n      if ((entry.finding_id ?? entry.fact_id) == null) results.skipped++;\n      else results.reinforced++;\n      break;\n    case \"release_files\": results.released++; break;\n    case \"question\": results.questions++; surfaced.push(`question: ${String(entry.content).slice(0, 160)}`); break;\n    case \"reinforced_note\":\n    case \"contradiction_note\": results.skipped++; surfaced.push(`${entry.type}: ${String(entry.content).slice(0, 160)}`); break;\n    default: results.errors++;\n  }\n}\n\n// --- arg parsing ---------------------------------------------------------\n\ninterface CliArgs {\n  projectRoot?: string;\n  pair?: string;\n  log?: string;\n  positional?: string;\n  allHistory: boolean;\n  dryRun: boolean;\n}\n\nfunction parseArgs(argv: string[]): CliArgs {\n  const args: CliArgs = { allHistory: false, dryRun: false };\n  for (let i = 0; i < argv.length; i++) {\n    const a = argv[i];\n    if (a === \"--pair\") args.pair = argv[++i];\n    else if (a === \"--log\") args.log = argv[++i];\n    else if (a === \"--project\") args.projectRoot = argv[++i];\n    else if (a === \"--all-history\") args.allHistory = true;\n    else if (a === \"--dry-run\") args.dryRun = true;\n    else if (!a.startsWith(\"--\") && args.positional === undefined) args.positional = a;\n  }\n  return args;\n}\n\n/**\n * Decide which logs to process from CLI args. A positional arg is either the\n * project root (a directory / contains .team11) or a single log file.\n */\nfunction resolveTargets(args: CliArgs): { projectRoot: string; logs: string[] } {\n  // A positional that points at a .md file is a single-log target; otherwise\n  // it's the project root (matches the secretary.md hook command shape, which\n  // passes ${CLAUDE_PROJECT_DIR}).\n  let projectRootHint = args.projectRoot;\n  let singleLog = args.log;\n\n  if (args.positional) {\n    if (args.positional.endsWith(\".md\")) {\n      singleLog = singleLog ?? args.positional;\n    } else {\n      projectRootHint = projectRootHint ?? args.positional;\n    }\n  }\n\n  const projectRoot = findProjectRoot(projectRootHint);\n\n  if (singleLog) {\n    return { projectRoot, logs: [resolveLogPathSafe(projectRoot, singleLog)] };\n  }\n  if (args.pair) {\n    const candidate = join(\"\\.team11\", \"logs\", `pair-${args.pair}.md`);\n    return { projectRoot, logs: [resolveLogPathSafe(projectRoot, candidate)] };\n  }\n  return { projectRoot, logs: discoverPairLogs(projectRoot) };\n}\n\n// --- main ----------------------------------------------------------------\n\nasync function main(): Promise<void> {\n  const args = parseArgs(process.argv.slice(2));\n  const { projectRoot, logs } = resolveTargets(args);\n  const dbPath = join(projectRoot, \".team11\", \"memory.db\");\n\n  // 0. Single-flight lock (write path only). --dry-run is read-only: it never\n  //    takes the lock, so it can never block a real run nor be blocked by one.\n  //    If another live copy holds the lock we exit 0 cleanly (NOT an error): the\n  //    holder scans every log, so this copy bailing loses no markers. The hook\n  //    that fires us must see exit 0 here, not a spurious failure.\n  if (!args.dryRun && !acquireLock(projectRoot)) {\n    console.log(JSON.stringify({ skipped: \"lock-held\" }));\n    return;\n  }\n\n  // Everything below mutates shared state (SQLite DB, logs, high-water mark) and\n  // MUST run under the lock. try/finally guarantees the lock is released even if\n  // processing throws; a hard crash that skips finally is covered by the 120s\n  // stale-steal in acquireLock(). --dry-run never acquired, so it never releases.\n  try {\n    // 1. Init DB (ensures ALL tables exist) — reused from db.ts.\n    const db = initDb(dbPath) as unknown as DbHandle;\n    console.error(`[process-pair-log] DB: ${dbPath}`);\n\n    // 2. Embeddings + Turso sync (best-effort; carrier still works without them).\n    //    initEmbeddings lets storeEmbedding actually populate the vector index;\n    //    write-and-sync.ts omits this, which is why findings written there are not\n    //    vector-searchable until the next seed run.\n    if (!args.dryRun) {\n      await initEmbeddings();\n    }\n    const syncConfig = args.dryRun ? null : loadSyncConfig(projectRoot);\n    if (syncConfig) {\n      await initSync(dbPath, syncConfig);\n      console.error(\"[process-pair-log] Turso sync connected\");\n    }\n\n    // 3. Process each target log.\n    const state = loadState(projectRoot);\n    const surfaced: string[] = [];\n    const perLog: LogResult[] = [];\n    for (const logPath of logs) {\n      try {\n        perLog.push(await processLog(db, projectRoot, logPath, state, args, surfaced));\n      } catch (err) {\n        console.error(`[process-pair-log] Failed on ${logPath}:`, err);\n        perLog.push({\n          log: relKey(projectRoot, logPath),\n          linesScanned: 0,\n          fromLine: 0,\n          processed: false,\n          reason: `error: ${String((err as Error)?.message ?? err)}`,\n          results: emptyResults(),\n        });\n      }\n    }\n\n    // 4. Persist state + push sync.\n    if (!args.dryRun) {\n      saveState(projectRoot, state);\n      if (syncConfig) {\n        await forceSync();\n        console.error(\"[process-pair-log] Turso sync pushed\");\n      }\n    }\n\n    // 5. Aggregate + report (stdout = machine-readable JSON; stderr = human log).\n    const totals = emptyResults();\n    for (const r of perLog) {\n      for (const k of Object.keys(totals) as (keyof WriteResults)[]) totals[k] += r.results[k];\n    }\n    console.log(\n      JSON.stringify({\n        dryRun: args.dryRun,\n        logsTargeted: logs.length,\n        logsProcessed: perLog.filter((r) => r.processed).length,\n        totals,\n        surfaced, // QUESTION FOR HUMAN / prose contradictions/reinforces for CEO\n        perLog,\n      }),\n    );\n\n    // 6. Clean up.\n    if (!args.dryRun) shutdownSync();\n    db.close();\n  } finally {\n    if (!args.dryRun) releaseLock(projectRoot);\n  }\n}\n\nmain().catch((err) => {\n  console.error(\"[process-pair-log] Fatal:\", err);\n  process.exit(1);\n});\n" });

  files.push({ path: "src/scripts/write-and-sync.ts", content: "/**\n * write-and-sync.ts — Standalone script for the Secretary agent.\n *\n * Ensures all DB tables exist (initDb), writes outbox entries,\n * triggers Turso sync so coworkers see changes within 60s.\n *\n * Usage: node dist/scripts/write-and-sync.js <outbox.json>\n *\n * The JSON file contains an array of outbox entries:\n * [\n *   { \"type\": \"fact\", \"title\": \"...\", \"content\": \"...\", \"confidence\": \"high\" },\n *   { \"type\": \"pheromone\", \"task\": \"...\", \"pair\": \"...\", \"difficulty\": \"LOW\", ... },\n *   { \"type\": \"gotcha\", \"title\": \"...\", \"content\": \"...\", \"evidence\": \"...\" },\n *   { \"type\": \"contradiction\", \"claim_a\": \"...\", \"source_a\": \"...\", ... },\n *   { \"type\": \"reinforced\", \"finding_id\": 42 },\n *   { \"type\": \"release_files\", \"pair_id\": \"cs-pair-1\" }\n * ]\n */\n\nimport { readFileSync, existsSync } from \"node:fs\";\nimport { join, dirname } from \"node:path\";\nimport { fileURLToPath } from \"node:url\";\nimport { initDb } from \"../db.js\";\nimport { loadSyncConfig, initSync, forceSync, shutdownSync } from \"../sync.js\";\nimport { initEmbeddings } from \"../embeddings.js\";\nimport { storeEmbedding } from \"../tools/store.js\";\n\nconst __dirname = dirname(fileURLToPath(import.meta.url));\n\nfunction findProjectRoot(): string {\n  if (process.env.PROJECT_ROOT) return process.env.PROJECT_ROOT;\n  let dir = __dirname;\n  for (let i = 0; i < 10; i++) {\n    if (existsSync(join(dir, \".team11\"))) return dir;\n    dir = dirname(dir);\n  }\n  throw new Error(\"Could not find project root\");\n}\n\ninterface OutboxEntry {\n  type: string;\n  [key: string]: unknown;\n}\n\nasync function main() {\n  const inputPath = process.argv[2];\n  if (!inputPath) {\n    console.error(\"Usage: node dist/scripts/write-and-sync.js <outbox.json>\");\n    process.exit(1);\n  }\n\n  if (!existsSync(inputPath)) {\n    console.error(`File not found: ${inputPath}`);\n    process.exit(1);\n  }\n\n  const projectRoot = findProjectRoot();\n  const dbPath = join(projectRoot, \".team11\", \"memory.db\");\n\n  // 1. Init DB — ensures ALL tables exist (including new ones)\n  const db = initDb(dbPath);\n  console.error(`[write-and-sync] DB initialized: ${dbPath}`);\n\n  // 1b. Init the embedding model so findings written below get vector\n  // embeddings (D6 fix). Without this, storeEmbedding() no-ops because\n  // embeddingsAvailable() is false, and Secretary-written knowledge stays\n  // invisible to vector recall. Non-blocking: if the model fails to load,\n  // embeddingsAvailable() stays false and we degrade to FTS-only (same as\n  // before this fix) rather than erroring.\n  await initEmbeddings();\n\n  // 2. Init Turso sync\n  const syncConfig = loadSyncConfig(projectRoot);\n  if (syncConfig) {\n    await initSync(dbPath, syncConfig);\n    console.error(\"[write-and-sync] Turso sync connected\");\n  } else {\n    console.error(\"[write-and-sync] No sync config — local-only mode\");\n  }\n\n  // 3. Read and process outbox entries\n  let entries: OutboxEntry[];\n  try {\n    entries = JSON.parse(readFileSync(inputPath, \"utf8\"));\n  } catch (err) {\n    console.error(`[write-and-sync] Failed to parse ${inputPath}:`, err);\n    process.exit(1);\n  }\n\n  if (!Array.isArray(entries)) {\n    console.error(\"[write-and-sync] Expected JSON array\");\n    process.exit(1);\n  }\n\n  const results = { facts: 0, pheromones: 0, gotchas: 0, contradictions: 0, reinforced: 0, released: 0, errors: 0 };\n\n  for (const entry of entries) {\n    try {\n      switch (entry.type) {\n        case \"fact\": {\n          const factTitle = entry.title as string;\n          const factContent = entry.content as string;\n          const factResult = db.prepare(\n            `INSERT INTO findings (title, content, type, confidence, importance, source_pair, tags)\n             VALUES (?, ?, 'fact', ?, 0.6, ?, ?)`\n          ).run(\n            factTitle,\n            factContent,\n            (entry.confidence as string) ?? \"high\",\n            (entry.pair as string) ?? null,\n            entry.tags ? JSON.stringify(entry.tags) : null\n          );\n          // D6: compute + store embedding the same way store_finding does\n          // (reuse storeEmbedding; same `${title} ${content}` shape).\n          await storeEmbedding(db, factResult.lastInsertRowid, `${factTitle} ${factContent}`);\n          results.facts++;\n          break;\n        }\n\n        case \"pheromone\":\n          db.prepare(\n            `INSERT INTO pheromones (task, pair, difficulty, files_touched, gotchas, duration_minutes, estimated_duration_minutes, rounds, findings_count, verdict_breakdown)\n             VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`\n          ).run(\n            entry.task as string,\n            (entry.pair as string) ?? null,\n            (entry.difficulty as string) ?? \"MEDIUM\",\n            JSON.stringify((entry.files_touched as string[]) ?? []),\n            JSON.stringify((entry.gotchas as string[]) ?? []),\n            (entry.actual_duration_min as number) ?? null,\n            (entry.estimated_duration_min as number) ?? null,\n            (entry.rounds as number) ?? null,\n            (entry.findings_count as number) ?? null,\n            entry.verdict_breakdown ? JSON.stringify(entry.verdict_breakdown) : null\n          );\n          results.pheromones++;\n          break;\n\n        case \"gotcha\": {\n          const gotchaTitle = entry.title as string;\n          const gotchaContent = entry.evidence\n            ? `${entry.content}\\n\\nEvidence: ${entry.evidence}`\n            : (entry.content as string);\n          const gotchaResult = db.prepare(\n            `INSERT INTO findings (title, content, type, confidence, importance, tags)\n             VALUES (?, ?, 'gotcha', 'high', 0.7, ?)`\n          ).run(\n            gotchaTitle,\n            gotchaContent,\n            entry.tags ? JSON.stringify(entry.tags) : null\n          );\n          // D6: embed the stored content (matches store_gotcha's\n          // `${title} ${fullContent}` shape) so it's vector-searchable.\n          await storeEmbedding(db, gotchaResult.lastInsertRowid, `${gotchaTitle} ${gotchaContent}`);\n          results.gotchas++;\n          break;\n        }\n\n        case \"contradiction\":\n          db.prepare(\n            `INSERT INTO contradictions (claim_a, source_a, claim_b, source_b, status)\n             VALUES (?, ?, ?, ?, 'OPEN')`\n          ).run(\n            entry.claim_a as string,\n            entry.source_a as string,\n            entry.claim_b as string,\n            entry.source_b as string\n          );\n          results.contradictions++;\n          break;\n\n        case \"reinforced\":\n          db.prepare(\n            `UPDATE findings SET confidence_score = 1.0, last_reinforced = datetime('now'), updated_at = datetime('now') WHERE id = ?`\n          ).run(entry.finding_id as number);\n          results.reinforced++;\n          break;\n\n        case \"release_files\":\n          db.prepare(\n            `UPDATE active_edits SET released_at = datetime('now'), status = 'merged' WHERE pair_id = ? AND released_at IS NULL`\n          ).run(entry.pair_id as string);\n          results.released++;\n          break;\n\n        default:\n          console.error(`[write-and-sync] Unknown entry type: ${entry.type}`);\n          results.errors++;\n      }\n    } catch (err) {\n      console.error(`[write-and-sync] Error processing ${entry.type} entry:`, err);\n      results.errors++;\n    }\n  }\n\n  // 4. Force Turso sync to push changes to cloud\n  if (syncConfig) {\n    await forceSync();\n    console.error(\"[write-and-sync] Turso sync pushed\");\n  }\n\n  // 5. Report results\n  console.log(JSON.stringify(results));\n\n  // 6. Clean up\n  shutdownSync();\n  db.close();\n}\n\nmain().catch((err) => {\n  console.error(\"[write-and-sync] Fatal:\", err);\n  process.exit(1);\n});\n" });

  files.push({ path: "src/scripts/consolidate-memory.ts", content: "/**\n * consolidate-memory.ts — Team11 \"sleep-time\" memory consolidation (E5).\n *\n * A standalone, DRY-RUN-BY-DEFAULT, recency-aware maintenance pass that keeps\n * the Team11 memory DB clean as it grows. Modeled structurally on the Secretary\n * carrier (process-pair-log.ts): same project-root resolution, the SAME atomic\n * single-flight lock (`.team11/_secretary.lock`), and the same reuse of the\n * existing primitives (`initDb`, `initEmbeddings`, `storeEmbedding`). It is a\n * ONE-SHOT processor, NOT a poll/sleep loop, and it registers no MCP tool / CLI.\n *\n * Three jobs (ALL default to report-only; pass --execute to apply):\n *\n *   1. RECENCY-AWARE DEDUPE. Within each `type`, find near-duplicate ACTIVE\n *      findings (cosine similarity of their stored embeddings >= --sim-threshold,\n *      default 0.93). For each near-dup cluster, KEEP the MOST RECENT (by\n *      last_reinforced, then created_at) and SUPERSEDE the older ones by setting\n *      their `superseded_by` to the keeper's id. RATIONALE: this is a restaurant\n *      domain — the newest confirmation of a fact wins; an older row must never\n *      outrank a newer one. Supersede is REVERSIBLE (it's a column write, not a\n *      delete; restore_finding clears it). The keeper's embedding is left as-is.\n *\n *   2. ABSOLUTIZE RELATIVE DATES. Best-effort, CONSERVATIVE: scan active\n *      findings' content for high-confidence relative-date phrases (\"today\",\n *      \"yesterday\", \"tomorrow\", \"N days/weeks ago\", \"last/next week\") and rewrite\n *      each to an absolute ISO date computed from THAT finding's own created_at.\n *      Never guesses. On --execute, the content is updated AND re-embedded via\n *      storeEmbedding so semantic search stays consistent (same discipline as the\n *      carrier). Word-boundary anchored; case-insensitive; idempotent (a rewrite\n *      injects an absolute date, which no longer matches the relative patterns).\n *\n *   3. SURFACE CONTRADICTIONS (report-only). Lists OPEN contradictions for human\n *      review. Auto-resolution is OUT OF SCOPE — never resolved here.\n *\n * SAFETY + CONCURRENCY:\n *   - DRY-RUN is the default and makes ZERO writes: no DB mutation, no lock, no\n *     file changes. It only prints a JSON report of what it WOULD merge/rewrite\n *     plus the contradiction list.\n *   - --execute acquires the SAME single-flight lock the carrier uses (atomic\n *     mkdir on <projectRoot>/.team11/_secretary.lock; if held by a live copy,\n *     exit 0 with {\"skipped\":\"lock-held\"}; released in finally; 120s stale-steal\n *     via CAS). This prevents racing the SubagentStop carrier. Dry-run takes NO\n *     lock, so it neither blocks nor is blocked by a real run.\n *   - No shell interpolation; no execSync. All SQL is parameterized.\n *\n * Usage:\n *   node dist/scripts/consolidate-memory.js [options]\n *\n * Options:\n *   --execute               Apply changes (supersede dups, rewrite dates). Default\n *                           is dry-run (report only, zero writes, no lock).\n *   --sim-threshold <n>     Cosine-similarity threshold for near-dup clustering\n *                           (0..1, default 0.93). Higher = stricter (fewer merges).\n *   --type <t>              Restrict dedupe to a single finding type (e.g. gotcha).\n *   --project <path>        Project root (default: PROJECT_ROOT env, else walk up).\n *   --json                  Force JSON-only output (default). Reserved for parity.\n *\n * Exit code 0 on success (including the clean lock-held bail). Non-zero only on\n * fatal setup errors (project root not found, DB init failure).\n */\n\nimport {\n  existsSync,\n  mkdirSync,\n  writeFileSync,\n  readFileSync,\n  renameSync,\n  rmSync,\n} from \"node:fs\";\nimport { join, dirname, resolve } from \"node:path\";\nimport { fileURLToPath } from \"node:url\";\nimport { initDb } from \"../db.js\";\nimport { initEmbeddings } from \"../embeddings.js\";\nimport { storeEmbedding } from \"../tools/store.js\";\nimport { loadSyncConfig, initSync, forceSync, shutdownSync } from \"../sync.js\";\n\nconst __dirname = dirname(fileURLToPath(import.meta.url));\n\nconst DEFAULT_SIM_THRESHOLD = 0.93;\n\n// --- project root --------------------------------------------------------\n// Mirrors process-pair-log.ts: explicit flag, then PROJECT_ROOT env, then walk\n// up from the script location looking for a .team11/ directory.\nfunction findProjectRoot(explicit?: string): string {\n  if (explicit) return resolve(explicit);\n  if (process.env.PROJECT_ROOT) return resolve(process.env.PROJECT_ROOT);\n  let dir = __dirname;\n  for (let i = 0; i < 10; i++) {\n    if (existsSync(join(dir, \".team11\"))) return dir;\n    const parent = dirname(dir);\n    if (parent === dir) break;\n    dir = parent;\n  }\n  throw new Error(\"Could not find project root (no .team11/ directory found)\");\n}\n\n// --- single-flight lock (shared with the Secretary carrier) --------------\n// IDENTICAL mechanism to process-pair-log.ts: an atomic mkdir on a directory is\n// the sole ownership signal (no { recursive: true } — recursive makes EEXIST\n// silent). Stale recovery is a compare-and-swap via atomic rename so two racing\n// stealers (or a stealer + a fresh holder) can never both believe they own it.\n// We share the SAME lock dir name so this pass and the carrier mutually exclude.\nconst LOCK_DIR_NAME = \"_secretary.lock\";\nconst LOCK_META_NAME = \"owner.json\";\nconst STALE_LOCK_MS = 120_000; // 120s: holder presumably crashed past this.\n\nfunction lockDirPath(projectRoot: string): string {\n  return join(projectRoot, \".team11\", LOCK_DIR_NAME);\n}\n\ninterface LockMeta {\n  pid: number;\n  acquired_at: string; // ISO-8601\n}\n\nfunction readLockMeta(dir: string): LockMeta | null {\n  try {\n    const raw = readFileSync(join(dir, LOCK_META_NAME), \"utf8\");\n    const parsed = JSON.parse(raw);\n    if (\n      parsed &&\n      typeof parsed === \"object\" &&\n      typeof parsed.acquired_at === \"string\"\n    ) {\n      return parsed as LockMeta;\n    }\n    return null;\n  } catch {\n    return null;\n  }\n}\n\n/**\n * Atomically create the lock dir and stamp ownership. Returns true on success.\n * Throws only on EEXIST (already held) — every other fs error propagates.\n */\nfunction tryCreateLock(dir: string): boolean {\n  try {\n    mkdirSync(dir); // atomic; NO { recursive: true }.\n  } catch (err) {\n    if ((err as NodeJS.ErrnoException)?.code === \"EEXIST\") return false;\n    throw err;\n  }\n  const meta: LockMeta = {\n    pid: process.pid,\n    acquired_at: new Date().toISOString(),\n  };\n  writeFileSync(join(dir, LOCK_META_NAME), JSON.stringify(meta) + \"\\n\");\n  return true;\n}\n\n/**\n * Acquire the single-flight lock. Returns true if we hold it, false if a live\n * copy holds it (caller should exit 0 cleanly). Stale-lock recovery uses a\n * CAS-via-atomic-rename, identical to the carrier — see process-pair-log.ts for\n * the full proof that double-acquire is impossible.\n */\nfunction acquireLock(projectRoot: string): boolean {\n  const dir = lockDirPath(projectRoot);\n\n  if (tryCreateLock(dir)) return true;\n\n  const meta = readLockMeta(dir);\n  const ageMs = meta ? Date.now() - Date.parse(meta.acquired_at) : Infinity;\n  const isStale = !meta || !Number.isFinite(ageMs) || ageMs > STALE_LOCK_MS;\n  if (!isStale) return false; // fresh lock, real holder — bail cleanly.\n\n  console.error(\n    `[consolidate-memory] Attempting steal of stale lock (age ${\n      Number.isFinite(ageMs) ? Math.round(ageMs / 1000) + \"s\" : \"unknown\"\n    }, pid ${meta?.pid ?? \"?\"})`,\n  );\n\n  const victim = `${dir}.stale-${process.pid}-${Date.now()}`;\n  try {\n    renameSync(dir, victim); // atomic; only one stealer can win this move.\n  } catch (err) {\n    if ((err as NodeJS.ErrnoException)?.code !== \"ENOENT\") {\n      console.error(\n        \"[consolidate-memory] Stale-lock rename failed (falling back to create):\",\n        err,\n      );\n    }\n    return tryCreateLock(dir);\n  }\n\n  // CAS check: confirm what we moved is the SAME stale instance we observed.\n  const moved = readLockMeta(victim);\n  const stillSameStale =\n    (!meta && !moved) ||\n    (!!meta && !!moved && moved.acquired_at === meta.acquired_at);\n  if (!stillSameStale) {\n    console.error(\n      \"[consolidate-memory] Lock changed under steal — restoring and bailing.\",\n    );\n    try {\n      renameSync(victim, dir);\n    } catch {\n      try {\n        rmSync(victim, { recursive: true, force: true });\n      } catch {\n        /* best-effort */\n      }\n    }\n    return false;\n  }\n\n  try {\n    rmSync(victim, { recursive: true, force: true });\n  } catch (err) {\n    console.error(\n      \"[consolidate-memory] Could not delete stolen stale lock (continuing):\",\n      err,\n    );\n  }\n  return tryCreateLock(dir);\n}\n\n/** Release the lock we hold. Best-effort + idempotent — never throws. */\nfunction releaseLock(projectRoot: string): void {\n  try {\n    rmSync(lockDirPath(projectRoot), { recursive: true, force: true });\n  } catch (err) {\n    console.error(\n      \"[consolidate-memory] WARNING: could not release lock (stale-steal will recover):\",\n      err,\n    );\n  }\n}\n\n// --- minimal DB shape ----------------------------------------------------\n// Structural subset of better-sqlite3 we rely on (same approach as the carrier,\n// which lets storeEmbedding accept the handle without a hard type dependency).\ninterface Stmt {\n  get(...params: unknown[]): unknown;\n  all(...params: unknown[]): unknown[];\n  run(...params: unknown[]): { changes: number; lastInsertRowid: number | bigint };\n}\ninterface DbHandle {\n  prepare(sql: string): Stmt;\n  close(): void;\n}\n\n// --- recency comparator (THE correctness-critical piece) -----------------\n//\n// \"Most recent\" = latest last_reinforced, tie-broken by latest created_at, final\n// tie-broken by HIGHER id (a later insert is newer). Returns the row that is the\n// NEWER of the two. Pure + side-effect-free so the auditor can unit-test it.\n//\n// Dates are ISO-ish strings from datetime('now') (\"YYYY-MM-DD HH:MM:SS\"); they\n// sort correctly lexicographically AND via Date.parse. We use Date.parse and\n// fall back to lexical compare if a timestamp is unparseable, so a malformed\n// last_reinforced can never silently make an OLDER row win.\nexport interface RecencyRow {\n  id: number;\n  created_at: string;\n  last_reinforced: string | null;\n}\n\nfunction tsValue(s: string | null | undefined): number {\n  if (!s) return -Infinity;\n  const t = Date.parse(s.includes(\"T\") ? s : s.replace(\" \", \"T\") + \"Z\");\n  return Number.isFinite(t) ? t : -Infinity;\n}\n\n/**\n * Returns true if `a` is STRICTLY more recent than `b` (a should be the keeper\n * over b). Newest wins by last_reinforced, then created_at, then id.\n */\nexport function isMoreRecent(a: RecencyRow, b: RecencyRow): boolean {\n  const ar = tsValue(a.last_reinforced ?? a.created_at);\n  const br = tsValue(b.last_reinforced ?? b.created_at);\n  if (ar !== br) return ar > br;\n  const ac = tsValue(a.created_at);\n  const bc = tsValue(b.created_at);\n  if (ac !== bc) return ac > bc;\n  // Final deterministic tiebreak: higher id = inserted later = newer.\n  return a.id > b.id;\n}\n\n/** Pick the single most-recent row from a non-empty cluster. */\nexport function pickKeeper<T extends RecencyRow>(rows: T[]): T {\n  return rows.reduce((best, r) => (isMoreRecent(r, best) ? r : best));\n}\n\n// --- relative-date absolutization (conservative) -------------------------\n//\n// Each pattern is matched case-insensitively and word-boundary anchored, then\n// replaced with an absolute YYYY-MM-DD computed from the finding's OWN\n// created_at. We only handle HIGH-CONFIDENCE phrases; anything ambiguous\n// (\"recently\", \"the other day\", \"soon\") is intentionally left untouched.\n\nfunction toIso(d: Date): string {\n  // UTC date portion only — findings record dates, not wall-clock instants.\n  return d.toISOString().slice(0, 10);\n}\n\nfunction addDays(base: Date, days: number): Date {\n  const d = new Date(base.getTime());\n  d.setUTCDate(d.getUTCDate() + days);\n  return d;\n}\n\nexport interface DateRewrite {\n  phrase: string;\n  replacement: string;\n}\n\n/**\n * Compute the conservative relative-date rewrites for one finding's content,\n * anchored on `createdAt`. Returns the rewritten content plus the list of\n * (phrase -> replacement) edits made. If createdAt is unparseable, returns the\n * content UNCHANGED with no edits (never guess against a bad anchor).\n *\n * Pure + deterministic so the auditor can unit-test it without a DB.\n */\nexport function absolutizeDates(\n  content: string,\n  createdAt: string,\n): { content: string; rewrites: DateRewrite[] } {\n  const anchorMs = tsValue(createdAt);\n  if (!Number.isFinite(anchorMs)) return { content, rewrites: [] };\n  const anchor = new Date(anchorMs);\n  const rewrites: DateRewrite[] = [];\n\n  let out = content;\n\n  // Helper: replace all occurrences of a regex, recording each concrete phrase\n  // and its computed absolute replacement. `offsetFor` maps the matched text to\n  // a day offset from the anchor (e.g. yesterday => -1).\n  const apply = (\n    re: RegExp,\n    offsetFor: (m: RegExpMatchArray) => number | null,\n  ): void => {\n    out = out.replace(re, (...args) => {\n      // String.replace passes (match, ...groups, offset, string). The matched\n      // text is args[0]; we only need the match + capture groups here.\n      const groups = args.slice(0, -2) as string[];\n      const m = groups as unknown as RegExpMatchArray;\n      const phrase = m[0];\n      const offset = offsetFor(m);\n      if (offset === null) return phrase; // un-handled -> leave verbatim\n      const replacement = toIso(addDays(anchor, offset));\n      rewrites.push({ phrase, replacement });\n      return replacement;\n    });\n  };\n\n  // \"N days ago\" / \"N weeks ago\" — numeric, highest confidence.\n  apply(/\\b(\\d{1,4})\\s+(day|days|week|weeks)\\s+ago\\b/gi, (m) => {\n    const n = parseInt(m[1], 10);\n    if (!Number.isFinite(n)) return null;\n    const unit = m[2].toLowerCase();\n    const mult = unit.startsWith(\"week\") ? 7 : 1;\n    return -(n * mult);\n  });\n\n  // Single-word relatives.\n  apply(/\\byesterday\\b/gi, () => -1);\n  apply(/\\btomorrow\\b/gi, () => +1);\n  // \"today\" => the anchor date itself.\n  apply(/\\btoday\\b/gi, () => 0);\n\n  // \"last week\" / \"next week\" — resolve to a point 7 days before/after the\n  // anchor. CONSERVATIVE: we do NOT attempt week-start arithmetic (locale +\n  // week-definition ambiguity); a 7-day shift is the defensible reading.\n  apply(/\\blast\\s+week\\b/gi, () => -7);\n  apply(/\\bnext\\s+week\\b/gi, () => +7);\n\n  return { content: out, rewrites };\n}\n\n// --- embedding load (real storage layout) --------------------------------\n// Embeddings are stored as BLOBs in `embedding_cache` (and mirrored in the\n// `findings_vec` vec0 table). There is NO separate \"embeddings\" table. We read\n// the cache BLOB and hand it straight to sqlite-vec's own vec_distance_cosine —\n// so we neither reinvent cosine nor re-embed for comparison.\n\ninterface FindingRow {\n  id: number;\n  title: string;\n  content: string;\n  type: string;\n  created_at: string;\n  last_reinforced: string | null;\n  has_embedding: number;\n}\n\ninterface DedupePlanItem {\n  type: string;\n  keeper: { id: number; title: string; created_at: string; last_reinforced: string | null };\n  superseded: Array<{\n    id: number;\n    title: string;\n    created_at: string;\n    last_reinforced: string | null;\n    similarity: number;\n  }>;\n}\n\n/**\n * Build dedupe clusters within a single type via union-find over the edges whose\n * cosine similarity >= threshold. Cosine similarity is computed by sqlite-vec's\n * vec_distance_cosine on the cached BLOBs (similarity = 1 - distance). Only\n * findings WITH a cached embedding participate; the rest cannot be compared and\n * are left untouched (reported in `skippedNoEmbedding`).\n */\nfunction planDedupeForType(\n  db: DbHandle,\n  rows: FindingRow[],\n  threshold: number,\n): { plan: DedupePlanItem[]; comparisons: number } {\n  const eligible = rows.filter((r) => r.has_embedding === 1);\n  const n = eligible.length;\n  const cosStmt = db.prepare(\n    `SELECT (1.0 - vec_distance_cosine(\n        (SELECT embedding FROM embedding_cache WHERE finding_id = ?),\n        (SELECT embedding FROM embedding_cache WHERE finding_id = ?)\n      )) AS sim`,\n  );\n\n  // Union-find over eligible indices.\n  const parent = eligible.map((_, i) => i);\n  const find = (x: number): number => {\n    while (parent[x] !== x) {\n      parent[x] = parent[parent[x]];\n      x = parent[x];\n    }\n    return x;\n  };\n  const union = (a: number, b: number): void => {\n    const ra = find(a);\n    const rb = find(b);\n    if (ra !== rb) parent[ra] = rb;\n  };\n\n  // Remember the best (max) similarity seen connecting each node into its\n  // cluster, for reporting. Keyed by finding id.\n  const bestSim = new Map<number, number>();\n  let comparisons = 0;\n\n  for (let i = 0; i < n; i++) {\n    for (let j = i + 1; j < n; j++) {\n      comparisons++;\n      const res = cosStmt.get(eligible[i].id, eligible[j].id) as\n        | { sim: number | null }\n        | undefined;\n      const sim = res && typeof res.sim === \"number\" ? res.sim : null;\n      if (sim === null) continue; // missing blob mid-flight — skip defensively\n      if (sim >= threshold) {\n        union(i, j);\n        const a = eligible[i].id;\n        const b = eligible[j].id;\n        if (sim > (bestSim.get(a) ?? -1)) bestSim.set(a, sim);\n        if (sim > (bestSim.get(b) ?? -1)) bestSim.set(b, sim);\n      }\n    }\n  }\n\n  // Group eligible rows by cluster root.\n  const clusters = new Map<number, FindingRow[]>();\n  for (let i = 0; i < n; i++) {\n    const root = find(i);\n    const arr = clusters.get(root) ?? [];\n    arr.push(eligible[i]);\n    clusters.set(root, arr);\n  }\n\n  const plan: DedupePlanItem[] = [];\n  for (const members of clusters.values()) {\n    if (members.length < 2) continue; // singletons are not duplicates\n    const keeper = pickKeeper(members);\n    const superseded = members\n      .filter((m) => m.id !== keeper.id)\n      .map((m) => ({\n        id: m.id,\n        title: m.title,\n        created_at: m.created_at,\n        last_reinforced: m.last_reinforced,\n        similarity: Math.round((bestSim.get(m.id) ?? 0) * 10000) / 10000,\n      }));\n    plan.push({\n      type: keeper.type,\n      keeper: {\n        id: keeper.id,\n        title: keeper.title,\n        created_at: keeper.created_at,\n        last_reinforced: keeper.last_reinforced,\n      },\n      superseded,\n    });\n  }\n  return { plan, comparisons };\n}\n\n// --- arg parsing ---------------------------------------------------------\ninterface CliArgs {\n  execute: boolean;\n  simThreshold: number;\n  type?: string;\n  projectRoot?: string;\n}\n\nfunction parseArgs(argv: string[]): CliArgs {\n  const args: CliArgs = { execute: false, simThreshold: DEFAULT_SIM_THRESHOLD };\n  for (let i = 0; i < argv.length; i++) {\n    const a = argv[i];\n    if (a === \"--execute\") args.execute = true;\n    else if (a === \"--json\") {\n      /* default output is already JSON; flag accepted for parity */\n    } else if (a === \"--sim-threshold\") {\n      const raw = argv[++i];\n      const v = Number(raw);\n      if (!Number.isFinite(v) || v <= 0 || v > 1) {\n        throw new Error(\n          `--sim-threshold must be a number in (0,1]; got ${JSON.stringify(raw)}`,\n        );\n      }\n      args.simThreshold = v;\n    } else if (a === \"--type\") args.type = argv[++i];\n    else if (a === \"--project\") args.projectRoot = argv[++i];\n    else if (a.startsWith(\"--\")) {\n      throw new Error(`Unknown flag: ${a}`);\n    }\n  }\n  return args;\n}\n\n// --- main ----------------------------------------------------------------\nasync function main(): Promise<void> {\n  const args = parseArgs(process.argv.slice(2));\n  const projectRoot = findProjectRoot(args.projectRoot);\n  const dbPath = join(projectRoot, \".team11\", \"memory.db\");\n\n  // 0. Single-flight lock — WRITE PATH ONLY. Dry-run is read-only and takes NO\n  //    lock, so it can never block a real run nor be blocked by one. If a live\n  //    copy (this pass OR the Secretary carrier) holds the lock we exit 0\n  //    cleanly with {\"skipped\":\"lock-held\"} — bailing loses no work because a\n  //    consolidation pass is idempotent and can simply run again later.\n  if (args.execute && !acquireLock(projectRoot)) {\n    console.log(JSON.stringify({ skipped: \"lock-held\" }));\n    return;\n  }\n\n  try {\n    // 1. Init DB (ensures ALL tables/extensions exist incl. sqlite-vec).\n    const db = initDb(dbPath) as unknown as DbHandle;\n    console.error(`[consolidate-memory] DB: ${dbPath}`);\n\n    // 2. Embeddings + sync only matter on --execute (re-embedding rewritten\n    //    content, pushing the result). Dry-run never mutates, so it skips both —\n    //    and crucially never loads the embedding model. (Cosine comparison uses\n    //    sqlite-vec on the already-stored BLOBs, so dedupe planning needs no\n    //    in-process embedder even in dry-run.)\n    let syncConfig = null;\n    if (args.execute) {\n      await initEmbeddings();\n      syncConfig = loadSyncConfig(projectRoot);\n      if (syncConfig) {\n        await initSync(dbPath, syncConfig);\n        console.error(\"[consolidate-memory] Turso sync connected\");\n      }\n    }\n\n    // 3. Load active findings (optionally filtered by type). Active = the same\n    //    predicate every other tool uses: superseded_by IS NULL OR = 0.\n    //    has_embedding flags whether a cached BLOB exists (only those can be\n    //    compared / re-embedded-on-rewrite-verify).\n    const findingSql =\n      `SELECT f.id, f.title, f.content, f.type, f.created_at, f.last_reinforced,\n              (SELECT COUNT(*) FROM embedding_cache ec WHERE ec.finding_id = f.id) AS has_embedding\n       FROM findings f\n       WHERE (f.superseded_by IS NULL OR f.superseded_by = 0)` +\n      (args.type ? ` AND f.type = ?` : ``) +\n      ` ORDER BY f.type, f.id`;\n    const findingParams = args.type ? [args.type] : [];\n    const findings = db.prepare(findingSql).all(...findingParams) as FindingRow[];\n\n    const byType = new Map<string, FindingRow[]>();\n    for (const f of findings) {\n      const arr = byType.get(f.type) ?? [];\n      arr.push(f);\n      byType.set(f.type, arr);\n    }\n\n    // 4. DEDUPE PLAN (read-only computation).\n    const dedupePlan: DedupePlanItem[] = [];\n    let totalComparisons = 0;\n    let skippedNoEmbedding = 0;\n    for (const rows of byType.values()) {\n      skippedNoEmbedding += rows.filter((r) => r.has_embedding !== 1).length;\n      const { plan, comparisons } = planDedupeForType(\n        db,\n        rows,\n        args.simThreshold,\n      );\n      totalComparisons += comparisons;\n      dedupePlan.push(...plan);\n    }\n\n    // 5. DATE-REWRITE PLAN (read-only computation).\n    interface RewritePlanItem {\n      id: number;\n      title: string;\n      created_at: string;\n      rewrites: DateRewrite[];\n      new_content: string;\n    }\n    const rewritePlan: RewritePlanItem[] = [];\n    for (const f of findings) {\n      const { content: newContent, rewrites } = absolutizeDates(\n        f.content,\n        f.created_at,\n      );\n      if (rewrites.length > 0 && newContent !== f.content) {\n        rewritePlan.push({\n          id: f.id,\n          title: f.title,\n          created_at: f.created_at,\n          rewrites,\n          new_content: newContent,\n        });\n      }\n    }\n\n    // 6. CONTRADICTIONS (report-only; never resolved here).\n    const openContradictions = db\n      .prepare(\n        `SELECT id, claim_a, source_a, claim_b, source_b, created_at\n         FROM contradictions WHERE status = 'OPEN'\n         ORDER BY created_at DESC LIMIT 100`,\n      )\n      .all() as Array<Record<string, unknown>>;\n\n    // 7. APPLY (only under --execute + lock).\n    let appliedSupersedes = 0;\n    let appliedRewrites = 0;\n    if (args.execute) {\n      const supersedeStmt = db.prepare(\n        `UPDATE findings SET superseded_by = ?, updated_at = datetime('now')\n         WHERE id = ? AND (superseded_by IS NULL OR superseded_by = 0)`,\n      );\n      const updateContentStmt = db.prepare(\n        `UPDATE findings SET content = ?, updated_at = datetime('now') WHERE id = ?`,\n      );\n\n      for (const item of dedupePlan) {\n        for (const dup of item.superseded) {\n          const r = supersedeStmt.run(item.keeper.id, dup.id);\n          appliedSupersedes += r.changes;\n        }\n      }\n\n      for (const item of rewritePlan) {\n        updateContentStmt.run(item.new_content, item.id);\n        appliedRewrites++;\n        // Keep the vector index consistent: re-embed the rewritten title+content\n        // (storeEmbedding hashes content and skips if unchanged, so this is safe\n        // and idempotent). Mirrors the carrier's post-write embed discipline.\n        await storeEmbedding(\n          db as never,\n          item.id,\n          `${item.title} ${item.new_content}`,\n        );\n      }\n\n      if (syncConfig) {\n        await forceSync();\n        console.error(\"[consolidate-memory] Turso sync pushed\");\n      }\n    }\n\n    // 8. Report (stdout = machine-readable JSON; stderr = human log).\n    const report = {\n      mode: args.execute ? \"execute\" : \"dry-run\",\n      project_root: projectRoot,\n      db: dbPath,\n      sim_threshold: args.simThreshold,\n      type_filter: args.type ?? null,\n      scanned: {\n        active_findings: findings.length,\n        types: byType.size,\n        comparisons: totalComparisons,\n        skipped_no_embedding: skippedNoEmbedding,\n      },\n      dedupe: {\n        clusters: dedupePlan.length,\n        would_supersede: dedupePlan.reduce(\n          (s, c) => s + c.superseded.length,\n          0,\n        ),\n        applied_supersedes: appliedSupersedes,\n        plan: dedupePlan,\n      },\n      date_rewrites: {\n        findings_affected: rewritePlan.length,\n        total_rewrites: rewritePlan.reduce((s, r) => s + r.rewrites.length, 0),\n        applied_rewrites: appliedRewrites,\n        plan: rewritePlan.map((r) => ({\n          id: r.id,\n          title: r.title,\n          created_at: r.created_at,\n          rewrites: r.rewrites,\n        })),\n      },\n      open_contradictions: {\n        count: openContradictions.length,\n        items: openContradictions,\n      },\n    };\n    console.log(JSON.stringify(report, null, 2));\n\n    if (args.execute && syncConfig) shutdownSync();\n    db.close();\n  } finally {\n    // Only --execute acquired the lock, so only --execute releases it. A hard\n    // crash that skips finally is covered by the 120s stale-steal in acquire.\n    if (args.execute) releaseLock(projectRoot);\n  }\n}\n\nmain().catch((err) => {\n  console.error(\"[consolidate-memory] Fatal:\", err);\n  process.exit(1);\n});\n" });


  // Write all files
  for (const file of files) {
    const fullPath = join(mcpServerDir, file.path);
    mkdirSync(join(fullPath, ".."), { recursive: true });
    writeFileSync(fullPath, file.content);
  }

  console.log("  Wrote " + files.length + " source files");
}
